@app.get("/api/report/monthly")
def api_report(request: Request, year: int, month: int, db=Depends(get_db)):
    u=require_login(request); dirs=user_dirs(u)
    ph=",".join("?"*len(dirs)) if dirs else "NULL"
    MOIS=["Janvier","Février","Mars","Avril","Mai","Juin","Juillet","Août","Septembre","Octobre","Novembre","Décembre"]
    # month=0 means full year report (ALL 12 months)
    if month == 0:
        txs=[dict(r) for r in db.execute(f"SELECT * FROM transactions WHERE year=? AND direction IN ({ph})",[year]+dirs).fetchall()] if dirs else []
        report_title = f"RAPPORT ANNUEL COMPLET CAMTEL — {year}"
        fname = f"rapport_annuel_{year}.csv"
    else:
        txs=[dict(r) for r in db.execute(f"SELECT * FROM transactions WHERE year=? AND strftime('%m',date_reception)=? AND direction IN ({ph})",[year,f"{month:02d}"]+dirs).fetchall()] if dirs else []
        report_title = f"RAPPORT MENSUEL CAMTEL — {MOIS[month-1].upper()} {year}"
        fname = f"rapport_{year}_{month:02d}.csv"
    bls=[dict(r) for r in db.execute(f"SELECT * FROM budget_lines WHERE year=? AND direction IN ({ph})",[year]+dirs).fetchall()] if dirs else []
    out=io.StringIO(); w=csv.writer(out)
    w.writerow([report_title])
    w.writerow([]); w.writerow(["RÉSUMÉ"])
    total_budget=sum(b["budget_cp"] for b in bls)
    total_engage=sum(t["montant"] for t in txs if t["status"]=="validated")
    total_pending=sum(t["montant"] for t in txs if t["status"]=="pending")
    w.writerow(["Budget total CP",total_budget])
    w.writerow(["Total engagé (validé)",total_engage])
    w.writerow(["En attente",total_pending])
    w.writerow(["Disponible",total_budget-total_engage])
    w.writerow(["Taux engagement",f"{round(total_engage/total_budget*100,1) if total_budget else 0}%"])
    w.writerow(["Nombre transactions",len(txs)])
    # If annual, add per-month breakdown
    if month == 0:
        w.writerow([]); w.writerow(["RÉCAPITULATIF PAR MOIS"])
        w.writerow(["Mois","Transactions","Montant engagé","Montant en attente"])
        for m in range(1,13):
            m_txs = [t for t in txs if t.get("date_reception","").split("-")[1:2] == [f"{m:02d}"]] if txs else []
            m_eng = sum(t["montant"] for t in m_txs if t["status"]=="validated")
            m_pnd = sum(t["montant"] for t in m_txs if t["status"]=="pending")
            if m_txs: w.writerow([MOIS[m-1],len(m_txs),m_eng,m_pnd])
    w.writerow([]); w.writerow(["DÉTAIL DES TRANSACTIONS"])
    w.writerow(["DATE","CODE/REF","DIRECTION","IMPUTATION","NATURE","INTITULE","MONTANT","STATUT","STATUT BUDGET"])
    for t in sorted(txs, key=lambda x: x.get("date_reception","") or ""):
        w.writerow([t["date_reception"],t["code_ref"],t["direction"],t["imputation"],t["nature"],t["intitule"],t["montant"],t["status"],t["statut_budget"]])
    out.seek(0)
    return StreamingResponse(iter([out.getvalue()]),media_type="text/csv",headers={"Content-Disposition":f"attachment; filename={fname}"})

