@app.post("/api/transactions/{tx_id}/attachments")
async def upload_attachment(request: Request, tx_id: int, file: UploadFile=File(...), db=Depends(get_db)):
    u = require_login(request)
    import base64, json as _json
    raw = await file.read()
    if len(raw) > 5*1024*1024: raise HTTPException(400,"Fichier trop grand (max 5MB)")
    b64 = base64.b64encode(raw).decode()
    mime = file.content_type or "application/octet-stream"
    tx = db.execute("SELECT * FROM transactions WHERE id=?",(tx_id,)).fetchone()
    if not tx: raise HTTPException(404,"Transaction non trouvée")
    try: atts = _json.loads(tx["attachments"] or "[]")
    except: atts = []
    atts.append({"name": file.filename, "mime": mime, "data": b64, "uploaded_by": u.get("name",""), "uploaded_at": date.today().isoformat()})
    db.execute("UPDATE transactions SET attachments=? WHERE id=?",(str(_json.dumps(atts)),tx_id))
    db.commit()
    return {"ok": True, "count": len(atts), "name": file.filename}

@app.delete("/api/transactions/{tx_id}/attachments/{att_idx}")
def delete_attachment(request: Request, tx_id: int, att_idx: int, db=Depends(get_db)):
    import json as _json
    require_login(request)
    tx = db.execute("SELECT * FROM transactions WHERE id=?",(tx_id,)).fetchone()
    if not tx: raise HTTPException(404,"Not found")
    try: atts = _json.loads(tx["attachments"] or "[]")
    except: atts = []
    if 0 <= att_idx < len(atts): atts.pop(att_idx)
    db.execute("UPDATE transactions SET attachments=? WHERE id=?",(str(_json.dumps(atts)),tx_id))
    db.commit()
    return {"ok": True, "count": len(atts)}

@app.get("/api/transactions/{tx_id}/attachments")
def get_attachments(request: Request, tx_id: int, db=Depends(get_db)):
    import json as _json
    require_login(request)
    tx = db.execute("SELECT attachments FROM transactions WHERE id=?",(tx_id,)).fetchone()
    if not tx: raise HTTPException(404,"Not found")
    try: atts = _json.loads(tx["attachments"] or "[]")
    except: atts = []
    # Return metadata only (no base64 data)
    return [{"index": i, "name": a["name"], "mime": a["mime"], "uploaded_by": a.get("uploaded_by",""), "uploaded_at": a.get("uploaded_at","")} for i,a in enumerate(atts)]

@app.get("/api/transactions/{tx_id}/attachments/{att_idx}/download")
def download_attachment(request: Request, tx_id: int, att_idx: int, db=Depends(get_db)):
    import json as _json, base64 as _b64
    require_login(request)
    tx = db.execute("SELECT attachments FROM transactions WHERE id=?",(tx_id,)).fetchone()
    if not tx: raise HTTPException(404,"Not found")
    try: atts = _json.loads(tx["attachments"] or "[]")
    except: atts = []
    if att_idx < 0 or att_idx >= len(atts): raise HTTPException(404,"Attachment not found")
    att = atts[att_idx]
    data = _b64.b64decode(att["data"])
    return StreamingResponse(iter([data]), media_type=att["mime"], headers={"Content-Disposition": f'attachment; filename="{att["name"]}"'})

