@app.get("/api/planning/export/{year}")
def api_pta_export(request: Request, year: int, direction: str="", btype: str="", db=Depends(get_db)):
    """Export PTA submissions to CSV (OPEX/CAPEX format)"""
    u = require_login(request)
    dirs = user_dirs(u)
    sql = "SELECT * FROM pta_submissions WHERE year=?"
    params = [year]
    if direction and direction in dirs: sql += " AND direction=?"; params.append(direction)
    elif dirs:
        ph = ",".join("?"*len(dirs))
        sql += f" AND direction IN ({ph})"; params += dirs
    if btype: sql += " AND budget_type=?"; params.append(btype)
    sql += " ORDER BY direction,sp_code,budget_type,action_code,tache_code"
    rows = [dict(r) for r in db.execute(sql, params).fetchall()]
    out = io.StringIO()
    w = csv.writer(out)
    w.writerow(["CODES ENTITES","SOUS PROGRAMME","ACTIONS CODE","ACTIONS LIBELLE","ACTIVITES CODE","ACTIVITES LIBELLE",
                "TACHES CODE","TACHES LIBELLE","COMPTES","NATURES","QTE","PU","MONTANT AE","MONTANT CP",
                "MENSUALISATION","TYPE BUDGET","STATUT","INITIÉ PAR","DATE"])
    for r in rows:
        w.writerow([r["direction"],r.get("sp_code",""),r.get("action_code",""),r.get("action_nom",""),
                    r.get("activite_code",""),r.get("activite_nom",""),
                    r["tache_code"],r["tache_nom"],r["compte"],r["nature"],
                    r["qte"],r["pu"],r["montant_ae"],r["montant_cp"],
                    r.get("mensualisation",""),r["budget_type"],r["status"],
                    r.get("created_by_name",""),r.get("created_at","")])
    out.seek(0)
    fname = f"PTA_{direction or 'ALL'}_{year}_{btype or 'ALL'}.csv"
    return StreamingResponse(iter([out.getvalue()]),media_type="text/csv",
                             headers={"Content-Disposition":f"attachment; filename={fname}"})

@app.get("/api/planning/summary/{year}")
def api_pta_summary(request: Request, year: int, db=Depends(get_db)):
    """Summary by direction and type for monitoring"""
    u = require_login(request)
    dirs = user_dirs(u)
    ph = ",".join("?"*len(dirs)) if dirs else "NULL"
    rows = db.execute(
        f"""SELECT direction, budget_type, status,
            COUNT(*) as nb_lignes, SUM(montant_ae) as total_ae, SUM(montant_cp) as total_cp
            FROM pta_submissions WHERE year=? AND direction IN ({ph})
            GROUP BY direction,budget_type,status ORDER BY direction""",
        [year]+dirs).fetchall() if dirs else []
    return [dict(r) for r in rows]

@app.post("/api/planning/import")
async def api_pta_import(request: Request, file: UploadFile=File(...), year: int=Form(...), 
                          direction: str=Form(...), db=Depends(get_db)):
    """Import OPEX/CAPEX CSV into planning submissions"""
    u = require_login(request)
    if u.get("role") not in ("admin","dcf_dir","dcf_sub","agent_plus"): raise HTTPException(403,"Accès refusé")
    raw = await file.read()
    content = None
    for enc in ("utf-8-sig","utf-8","latin-1","cp1252"):
        try: content = raw.decode(enc); break
        except: pass
    if not content: raise HTTPException(400,"Cannot decode file")
    reader = csv.reader(io.StringIO(content))
    rows = list(reader)
    created = 0; errors = []
    
    # Detect if it's a standard CAPEX/OPEX file (2 header rows) or our export format
    if len(rows) > 2 and rows[0][0].strip() == "CODES ENTITES":
        # Standard CAMTEL CAPEX/OPEX format
        btype = "CAPEX" if any("CAPEX" in r[0] for r in rows[:5]) else "OPEX"
        for i, r in enumerate(rows[2:], 3):
            if not r or not r[0].strip(): continue
            def g(idx): return r[idx].strip().replace("","'").replace("","Œ") if len(r)>idx else ""
            tache_code = g(8); tache_nom = g(9)
            if not tache_code: continue
            compte = g(10); nature = g(11)
            try:
                montant_ae = float(g(14).replace(",","").replace(" ",""))
            except: montant_ae = 0
            cp2025 = 0
            try: cp2025 = float(g(18).replace(",","").replace(" ",""))
            except: pass
            ent = g(3) or direction
            db.execute("""INSERT INTO pta_submissions 
                (direction,year,sp_code,action_code,action_nom,activite_code,activite_nom,
                 tache_code,tache_nom,compte,nature,budget_type,qte,pu,montant_ae,montant_cp,
                 status,created_by,created_by_name)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,1,?,?,?,?,?,?)""",
                (ent,year,g(1),g(4),g(5),g(6),g(7),tache_code,tache_nom,
                 compte,nature,btype,montant_ae,cp2025,"validated",u.get("u",""),u.get("name","")))
            created += 1
    else:
        # Our export format
        for i, r in enumerate(rows[1:], 2):
            if not r or not r[0].strip(): continue
            def g(idx): return r[idx].strip() if len(r)>idx else ""
            try:
                db.execute("""INSERT INTO pta_submissions 
                    (direction,year,sp_code,action_code,action_nom,activite_code,activite_nom,
                     tache_code,tache_nom,compte,nature,budget_type,qte,pu,montant_ae,montant_cp,
                     mensualisation,status,created_by,created_by_name)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                    (g(0),year,g(1),g(2),g(3),g(4),g(5),g(6),g(7),g(8),g(9),
                     g(15),float(g(10) or 0),float(g(11) or 0),
                     float(g(12) or 0),float(g(13) or 0),g(14),g(16),u.get("u",""),u.get("name","")))
                created += 1
            except Exception as e: errors.append(f"Row {i}: {e}")
    db.commit()
    return {"created": created, "errors": errors[:10]}


@app.get("/fiche-imputation", response_class=HTMLResponse)
def fiche_imputation(request: Request, ids: str, db=Depends(get_db)):
    require_login(request)
    tx_ids=[int(i.strip()) for i in ids.split(",") if i.strip().isdigit()]
    txs=[]
    for tid in tx_ids[:20]:
        t=db.execute("SELECT * FROM transactions WHERE id=?",(tid,)).fetchone()
        if t: txs.append(dict(t))
    pages="".join(_fiche_imputation_block(t) for t in txs)
    n=len(txs)
    css=IMP_CSS_STR
    head=f"<!doctype html><html lang='fr'><head><meta charset='utf-8'/><title>Fiche d'Imputation</title><style>{css}</style></head><body>"
    nav=f"<div class='noprint'><button onclick='window.print()'>\U0001F5A8 Imprimer</button><button onclick='window.close()' style='background:#64748b'>Fermer</button><span style='color:#93c5fd;font-size:12px'>{n} fiche(s)</span></div>"
    return HTMLResponse(head+nav+pages+"</body></html>")


def _fiche_imputation_block(t):
    LOGO = "data:image/png;base64,"
    designation = t.get("designation") or "NC"
    montant = float(t.get("montant") or 0)
    code_ref = t.get("code_ref","")
    dirn = t.get("direction","")
    intitule = t.get("intitule","") or t.get("description","") or ""
    num_compte = t.get("num_compte","") or ""
    date_r = t.get("date_reception","")
    amt_str = fmt_fcfa(montant)
    entries=[]
    if designation=="OM":
        nd=t.get("number_of_days","") or ""
        apd=t.get("amount_per_day","") or ""
        apd_s=fmt_fcfa(apd) if apd else ""
        entries=[
            {"num":"6057","lib":f"FM {dirn} — {intitule} ({nd} jr(s) x {apd_s} FCFA/jr)","deb":amt_str,"cre":""},
            {"num":"42860010","lib":f"Engagement FM {code_ref}","deb":"","cre":amt_str},
        ]
    elif designation=="NC":
        entries=[
            {"num":num_compte or "6...........","lib":f"NC — {intitule}","deb":amt_str,"cre":""},
            {"num":"42131150","lib":f"Avance/NC {code_ref} — {dirn}","deb":"","cre":amt_str},
        ]
    elif designation=="BC":
        entries=[
            {"num":num_compte or "60..........","lib":f"BC — {intitule}","deb":amt_str,"cre":""},
            {"num":"40110000","lib":f"Fournisseur BC {code_ref}","deb":"","cre":amt_str},
        ]
    elif designation=="LC":
        entries=[
            {"num":num_compte or "63..........","lib":f"LC — {intitule}","deb":amt_str,"cre":""},
            {"num":"40110000","lib":f"Fournisseur LC {code_ref}","deb":"","cre":amt_str},
        ]
    else:  # MARCHE
        entries=[
            {"num":num_compte or "60/24.......","lib":f"MARCHE — {intitule}","deb":amt_str,"cre":""},
            {"num":"40420010","lib":f"Fournisseur Marché {code_ref}","deb":"","cre":amt_str},
        ]
    n_empty=max(15-len(entries),8)
    rows=""
    for e in entries:
        rows+=f"<tr><td class='num'>{e['num']}</td><td>{e['lib']}</td><td class='debit'>{e['deb']}</td><td class='credit'>{e['cre']}</td></tr>"
    for _ in range(n_empty):
        rows+="<tr><td class='num'>&nbsp;</td><td>&nbsp;</td><td class='debit'>&nbsp;</td><td class='credit'>&nbsp;</td></tr>"
    return (
        "<div class='page'>"
        f"<div class='imp-logo'><img src='{LOGO}' alt='CAMTEL'/></div>"
        "<div class='imp-title'><h1>FICHE D\'IMPUTATION</h1></div>"
        "<div class='service-doc'>Service de la Documentation</div>"
        f"<div class='imp-meta'>"
        f"<div class='imp-meta-item'><span class='imp-meta-label'>DATE</span>&nbsp;<span class='imp-meta-val'>{date_r}</span></div>"
        f"<div class='imp-meta-item'><span class='imp-meta-label'>PIÈCE N°</span>&nbsp;<span class='imp-meta-val'>{code_ref}</span></div>"
        "</div>"
        "<table class='imp-table'><thead><tr>"
        "<th style='width:26%'>N° DE COMPTE</th><th style='width:46%'>LIBELLÉ</th>"
        "<th style='width:14%'>DÉBIT</th><th style='width:14%'>CRÉDIT</th>"
        f"</tr></thead><tbody>{rows}</tbody></table>"
        f"<div class='imp-totals'><span>TOTAL DÉBIT : {amt_str} FCFA</span><span>TOTAL CRÉDIT : {amt_str} FCFA</span></div>"
        "</div>"
    )



@app.get("/fiche", response_class=HTMLResponse)
def fiche(request: Request, ids: str, db=Depends(get_db)):
    u = require_login(request)
    tx_ids=[int(i.strip()) for i in ids.split(",") if i.strip().isdigit()]
    txs=[]
    for tid in tx_ids[:20]:
        t=db.execute("SELECT * FROM transactions WHERE id=?",(tid,)).fetchone()
        if t: txs.append(dict(t))
    pages=[]
    for i in range(0,len(txs),2):
        pair=txs[i:i+2]
        blocks="".join(_fiche_block(t,db) for t in pair)
        if len(pair)==1: blocks+="<div style='height:5mm'></div>"
        pages.append(f"<div class='page'>{blocks}</div>")
    FICHE_CSS="""
*{box-sizing:border-box;margin:0;padding:0;}
body{font-family:Arial,Helvetica,sans-serif;font-size:9pt;color:#000;background:#e5e7eb;}
.noprint{padding:8px 12px;background:#1e3a8a;display:flex;gap:8px;align-items:center;position:sticky;top:0;z-index:99;}
.noprint button{padding:7px 16px;background:#00b0e8;color:#fff;border:none;border-radius:5px;cursor:pointer;font-weight:800;font-size:12px;}
.noprint button.cl{background:#475569;}
/* Each page holds exactly 2 fiches */
.page{width:210mm;height:297mm;padding:5mm 7mm;display:flex;flex-direction:column;gap:3mm;page-break-after:always;background:#fff;}
.fiche{border:2px solid #003e7e;padding:3mm 4mm;flex:1;display:flex;flex-direction:column;position:relative;overflow:hidden;}
/* Watermark */
.wm{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%) rotate(-20deg);pointer-events:none;z-index:0;user-select:none;}
/* All content above watermark */
.fhdr,.sec,.box,.amt-box,.solde-box,.dispo,.att-box,.initby,.signs{position:relative;z-index:1;}
/* Header */
.fhdr{display:flex;align-items:center;gap:5px;padding-bottom:2mm;border-bottom:2.5px solid #003e7e;margin-bottom:2mm;}
.flogo{background:linear-gradient(135deg,#003e7e,#00b0e8);border-radius:5px;padding:3px;flex-shrink:0;}
.ftitle{flex:1;}
.ftitle h1{font-size:8.5pt;font-weight:900;color:#003e7e;line-height:1.2;}
.ftitle p{font-size:7pt;color:#64748b;margin-top:1px;}
.fref{text-align:right;font-size:7.5pt;font-weight:700;color:#003e7e;flex-shrink:0;white-space:nowrap;}
/* Bilingual section headers */
.sec{background:#003e7e;color:#fff;padding:1.5px 5px;font-size:7.5pt;font-weight:900;text-transform:uppercase;margin:1.5mm 0 1mm;letter-spacing:.05em;}
.sec .en{font-weight:900;}
.sec .fr{font-weight:400;opacity:.85;}
.sec .sep{margin:0 4px;opacity:.5;}
/* Info box */
.box{border:1px solid #334155;padding:1.5mm 3mm;margin-bottom:1mm;}
.r{display:flex;border-bottom:1px dotted #e2e8f0;padding:1px 0;align-items:flex-start;}
.r:last-child{border-bottom:none;}
.rl{color:#334155;min-width:140px;font-size:7.5pt;flex-shrink:0;padding-right:4px;}
.rv{flex:1;font-size:8pt;word-break:break-word;}
.mono{font-family:"Courier New",monospace;font-weight:700;}
.small{font-size:7pt;}
/* Amount box */
.amt-box{background:linear-gradient(135deg,#f0f7ff,#e0effe);border:2px solid #003e7e;padding:2mm 3mm;margin:1.5mm 0;text-align:center;}
.amt-lbl{font-size:7pt;font-weight:800;color:#475569;letter-spacing:.12em;text-transform:uppercase;}
.amt-val{font-size:15pt;font-weight:900;color:#003e7e;letter-spacing:1px;margin-top:1mm;font-family:"Courier New",monospace;}
/* Balance table */
.solde-box{border:1px solid #334155;padding:1.5mm 3mm;margin:1mm 0;}
.solde-r{display:flex;justify-content:space-between;padding:1px 0;font-size:8pt;border-bottom:1px dotted #f1f5f9;align-items:center;}
.solde-r:last-child{border-bottom:none;}
.solde-r.final{font-weight:900;font-size:9pt;margin-top:1mm;border-top:1.5px solid #334155;padding-top:1.5mm;}
/* Available / Disponible */
.dispo{border:2px solid #000;padding:1.5mm 4mm;display:flex;justify-content:space-between;align-items:center;margin:1.5mm 0;}
.dispo-lbl{font-weight:900;font-size:10pt;letter-spacing:.1em;}
.chks{display:flex;gap:14px;font-size:9.5pt;font-weight:800;}
.chk{display:flex;align-items:center;gap:5px;}
.chkb{width:13px;height:13px;border:2px solid #000;display:inline-flex;align-items:center;justify-content:center;font-size:9pt;font-weight:900;}
.chkb.ok{border-color:#16a34a;background:#dcfce7;color:#16a34a;}
.chkb.nok{border-color:#dc2626;background:#fee2e2;color:#dc2626;}
/* Attachments */
.att-box{border:1px dashed #334155;padding:1.5mm 3mm;margin:1mm 0;min-height:8mm;font-size:7.5pt;}
.att-item{padding:1px 0;color:#1e3a8a;font-weight:600;}
.att-meta{color:#64748b;font-weight:400;}
.att-none{color:#94a3b8;font-style:italic;font-size:7.5pt;}
/* Initiated by */
.initby{font-size:7.5pt;color:#475569;text-align:right;margin:1mm 0;}
/* Single signature box - BUDGET SERVICE/SAAF only */
.signs{margin-top:auto;}
.sign-only{border:1.5px solid #003e7e;padding:2mm 3mm;min-height:35mm;background:linear-gradient(180deg,#f8faff,#fff);}
.sign-only>label{font-size:8pt;font-weight:900;text-transform:uppercase;color:#003e7e;display:block;letter-spacing:.06em;border-bottom:1px solid #e2e8f0;padding-bottom:1.5mm;margin-bottom:1.5mm;}
@media print{
  .noprint{display:none!important;}
  body{background:#fff;}
  .page{padding:4mm 6mm;width:210mm;height:297mm;}
  @page{size:A4 portrait;margin:0;}
}"""
    return HTMLResponse(f"""<!doctype html><html lang='fr'><head><meta charset='utf-8'/>
<title>Fiches DCF</title><style>{FICHE_CSS}</style></head><body>
<div class='noprint'>
  <button onclick='window.print()'>🖨 Imprimer / PDF</button>
  <button onclick='window.close()' style='background:#64748b'>Fermer</button>
  <span style='font-size:12px;color:#64748b'>{len(txs)} fiche(s) — {len(pages)} page(s) A4</span>
</div>
{"".join(pages)}
</body></html>""")

def _fiche_block(t, db):
    import json as _json
    bl=db.execute("SELECT * FROM budget_lines WHERE imputation=? AND year=?",(t["imputation"],t["year"])).fetchone()
    prevision=bl["budget_cp"] if bl else 0
    libelle_bl=bl["libelle"] if bl else (t["imputation"] or "—")
    eng_before=db.execute("SELECT COALESCE(SUM(montant),0) FROM transactions WHERE imputation=? AND year=? AND status='validated' AND id<?",(t["imputation"],t["year"],t["id"])).fetchone()[0]
    solde_avant=prevision-eng_before; solde_apres=solde_avant-t["montant"]; dispo=solde_apres>=0
    gc="#16a34a" if dispo else "#dc2626"
    oui_chk=f"<div class='chkb ok'>✓</div>" if dispo else "<div class='chkb'></div>"
    non_chk=f"<div class='chkb nok'>✓</div>" if not dispo else "<div class='chkb'></div>"
    # Attachments
    try: atts=_json.loads(t.get("attachments") or "[]")
    except: atts=[]
    att_html="".join(f"<div class='att-item'>📎 {a['name']} <span class='att-meta'>({a.get('uploaded_by','')}, {a.get('uploaded_at','')})</span></div>" for a in atts) if atts else "<div class='att-none'>Aucun document joint / No supporting document attached</div>"
    return f"""
<div class='fiche'>
  <!-- Watermark logo -->
  <div class='wm'><img src='data:image/png;base64,' style='width:220px;height:220px;object-fit:contain;opacity:.04' alt=''/></div>

  <!-- HEADER -->
  <div class='fhdr'>
    <div class='flogo'><img src='data:image/png;base64,' style='width:38px;height:38px;object-fit:contain;filter:brightness(0) invert(1)' alt='CAMTEL'/></div>
    <div class='ftitle'>
      <h1>CAMTEL — {t.get("direction","—")} | BUDGET MONITORING SHEET / FICHE DE SUIVI BUDGÉTAIRE</h1>
      <p>SAAF / DCF / BUDGET CONTROL — CONTRÔLE BUDGÉTAIRE</p>
    </div>
    <div class='fref'>Réf: {t["code_ref"]}<br/>{t["date_reception"]}</div>
  </div>

  <!-- BUDGETARY ACCOUNT / COMPTE BUDGÉTAIRE -->
  <div class='sec'>
    <span class='en'>BUDGETARY ACCOUNT</span> <span class='sep'>|</span>
    <span class='fr'>COMPTE BUDGÉTAIRE</span>
  </div>
  <div class='box'>
    <div class='r'>
      <span class='rl'><b>Account forecast / Prévision:</b></span>
      <span class='rv mono'><b>{fmt_fcfa(prevision)} FCFA</b></span>
    </div>
    <div class='r'>
      <span class='rl'>Accounting note – Opening balance / Note comptabilité – Solde initial:</span>
      <span class='rv mono'>{fmt_fcfa(prevision)} FCFA</span>
    </div>
  </div>

  <!-- REFERENCE / DESCRIPTION / COMMITMENT -->
  <div class='sec'>
    <span class='en'>REFERENCE / DESCRIPTION / COMMITMENT</span> <span class='sep'>|</span>
    <span class='fr'>RÉFÉRENCE / LIBELLÉ / ENGAGEMENT</span>
  </div>
  <div class='box'>
    <div class='r'><span class='rl'>Account ref. / Réf. compte:</span><span class='rv mono small'>{t["imputation"]}</span></div>
    <div class='r'><span class='rl'>Code / File Ref. / Réf. dossier:</span><span class='rv'><b>{t["code_ref"]}</b></span></div>
    <div class='r'><span class='rl'>Direction:</span><span class='rv'><b>{t["direction"]}</b></span></div>
    <div class='r'><span class='rl'>Date:</span><span class='rv'>{t["date_reception"]}</span></div>
    <div class='r'><span class='rl'>Nature:</span><span class='rv'>{t["nature"]}</span></div>
    <div class='r'><span class='rl'>Label(s) / Libellé(s):</span><span class='rv'><b>{libelle_bl}</b></span></div>
    <div class='r'><span class='rl'>Object / Description / Objet:</span><span class='rv'>{t["description"] or t["intitule"] or "—"}</span></div>
  </div>

  <!-- AMOUNT / MONTANT -->
  <div class='amt-box'>
    <div class='amt-lbl'>AMOUNT OF COMMITMENT / MONTANT DE L'ENGAGEMENT</div>
    <div class='amt-val'>{fmt_fcfa(t["montant"])} FCFA</div>
  </div>

  <!-- BALANCE TABLE / TABLEAU DES SOLDES -->
  <div class='solde-box'>
    <div class='solde-r'>
      <span>Balance before commitment / Solde avant engagement:</span>
      <span class='mono'>{fmt_fcfa(solde_avant)} FCFA</span>
    </div>
    <div class='solde-r'>
      <span>Commitment / Engagement:</span>
      <span class='mono'>- {fmt_fcfa(t["montant"])} FCFA</span>
    </div>
    <div class='solde-r final'>
      <span>FINAL ACCOUNT BALANCE / SOLDE FINAL DU COMPTE:</span>
      <span class='mono' style='color:{gc}'>{fmt_fcfa(solde_apres)} FCFA</span>
    </div>
  </div>

  <!-- AVAILABLE / DISPONIBLE -->
  <div class='dispo'>
    <div class='dispo-lbl'>AVAILABLE / DISPONIBLE</div>
    <div class='chks'>
      <div class='chk'>{oui_chk} YES / OUI</div>
      <div class='chk'>{non_chk} NO / NON</div>
    </div>
  </div>

  <!-- SUPPORTING DOCUMENTS / PIÈCES JUSTIFICATIVES -->
  <div class='sec'>
    <span class='en'>SUPPORTING DOCUMENTS</span> <span class='sep'>|</span>
    <span class='fr'>PIÈCES JUSTIFICATIVES</span>
  </div>
  <div class='att-box'>{att_html}</div>

  <!-- SIGNATURE -->
  <div class='initby'>Initiated by / Initié par : <b>{t.get("created_by_name") or t.get("created_by","—")}</b></div>
  <div class='signs'>
    <div class='sign sign-only'>
      <label>VISA BUDGET SERVICE / SAAF — CONTRÔLEUR BUDGÉTAIRE</label>
      <div style='display:grid;grid-template-columns:1fr 1fr;gap:4mm;margin-top:2mm'>
        <div>
          <div style='font-size:7pt;color:#475569;font-weight:700'>NAME / NOM:</div>
          <div style='border-bottom:1px solid #334155;height:10mm;margin-top:1mm'></div>
        </div>
        <div>
          <div style='font-size:7pt;color:#475569;font-weight:700'>DATE:</div>
          <div style='border-bottom:1px solid #334155;height:10mm;margin-top:1mm'></div>
        </div>
      </div>
      <div style='margin-top:2mm'>
        <div style='font-size:7pt;color:#475569;font-weight:700'>SIGNATURE / CACHET:</div>
        <div style='border-bottom:1px solid #334155;height:14mm;margin-top:1mm'></div>
      </div>
    </div>
  </div>
</div>"""

































LOGIN_HTML = '<!doctype html>\n<html lang=\'fr\' id=\'lpage\'><head><meta charset=\'utf-8\'/>\n<meta name=\'viewport\' content=\'width=device-width,initial-scale=1\'/>\n<title>CAMTEL - Connexion / Login</title>\n<style>\n*{box-sizing:border-box;margin:0;padding:0;}\nbody{font-family:\'Segoe UI\',system-ui,sans-serif;background:linear-gradient(135deg,#0a1f4e 0%,#1f4d8f 55%,#00b0e8 100%);min-height:100vh;display:flex;align-items:center;justify-content:center;}\n.card{background:#fff;border-radius:16px;padding:32px 30px;width:440px;box-shadow:0 20px 60px rgba(0,0,0,.3);}\n.lrow{display:flex;align-items:center;gap:14px;margin-bottom:20px;}\n.llogo{width:64px;height:64px;object-fit:contain;flex-shrink:0;}\nh2{font-size:17px;font-weight:800;color:#0f2a5e;}\n.sub{font-size:10px;color:#64748b;margin-top:2px;}\n.lang-row{display:flex;gap:6px;justify-content:flex-end;margin-bottom:14px;}\n.lang-btn{padding:4px 12px;border-radius:20px;border:1.5px solid #e2e8f0;background:#f8fafc;cursor:pointer;font-size:11px;font-weight:700;color:#475569;}\n.lang-btn.active{background:#1f4d8f;color:#fff;border-color:#1f4d8f;}\nlabel{display:block;font-size:11px;font-weight:700;color:#475569;margin:12px 0 4px;text-transform:uppercase;letter-spacing:.04em;}\ninput[type=text],input[type=password]{width:100%;padding:11px 12px;border-radius:8px;border:1.5px solid #e2e8f0;font-size:14px;font-family:inherit;}\ninput:focus{outline:none;border-color:#00b0e8;box-shadow:0 0 0 3px rgba(0,176,232,.12);}\n.submit-btn{width:100%;padding:12px;border-radius:8px;background:linear-gradient(135deg,#1f4d8f,#00b0e8);color:#fff;border:none;cursor:pointer;font-size:14px;font-weight:700;margin-top:18px;}\n.submit-btn:hover{opacity:.92;}\n.hint{color:#94a3b8;font-size:11px;margin-top:12px;text-align:center;}\n.err{background:#fee2e2;color:#dc2626;padding:9px 12px;border-radius:6px;font-size:12px;margin-bottom:10px;border-left:3px solid #dc2626;}\n.divider{border:none;border-top:1px solid #f1f5f9;margin:16px 0;}\n</style></head>\n<body><div class=\'card\'>\n  <div class=\'lang-row\'>\n    <button class=\'lang-btn active\' id=\'lb-fr\' onclick="setLang(\'fr\')">🇫🇷 Français</button>\n    <button class=\'lang-btn\' id=\'lb-en\' onclick="setLang(\'en\')">🇬🇧 English</button>\n  </div>\n  <div class=\'lrow\'>\n    <img src=\'data:image/png;base64,\' class=\'llogo\' alt=\'CAMTEL\'/>\n    <div>\n      <h2>CAMTEL</h2>\n      <div class=\'sub\' id=\'l-sub\'>Gestion Budgétaire — SAAF / DCF / Contrôle Budgétaire</div>\n    </div>\n  </div>\n  __ERR__\n  <form method=\'post\' action=\'/api/login\' id=\'lform\'>\n    <label id=\'l-user\'>IDENTIFIANT</label>\n    <input name=\'username\' id=\'inp-user\' placeholder=\'admin\' required autofocus autocomplete=\'username\'/>\n    <label id=\'l-pass\'>MOT DE PASSE</label>\n    <input name=\'password\' type=\'password\' id=\'inp-pass\' placeholder=\'••••••••\' required autocomplete=\'current-password\'/>\n    <button type=\'submit\' class=\'submit-btn\' id=\'l-btn\'>Se connecter →</button>\n  </form>\n  <div class=\'hint\' id=\'l-hint\'>Contactez l\'administrateur pour vos accès.</div>\n</div>\n<script>\nconst LT={\n  fr:{sub:\'Gestion Budgétaire — SAAF / DCF / Contrôle Budgétaire\',user:\'IDENTIFIANT\',pass:\'MOT DE PASSE\',btn:\'Se connecter →\',hint:"Contactez l\'administrateur pour vos accès.",uph:\'admin\',pph:\'••••••••\'},\n  en:{sub:\'Budget Management — SAAF / DCF / Budget Control\',user:\'USERNAME\',pass:\'PASSWORD\',btn:\'Sign in →\',hint:\'Contact your administrator for access.\',uph:\'admin\',pph:\'••••••••\'}\n};\nlet curL=localStorage.getItem(\'camtel_lang\')||\'fr\';\nfunction setLang(l){\n  curL=l;localStorage.setItem(\'camtel_lang\',l);\n  const tx=LT[l];\n  document.getElementById(\'l-sub\').textContent=tx.sub;\n  document.getElementById(\'l-user\').textContent=tx.user;\n  document.getElementById(\'l-pass\').textContent=tx.pass;\n  document.getElementById(\'l-btn\').textContent=tx.btn;\n  document.getElementById(\'l-hint\').textContent=tx.hint;\n  document.getElementById(\'inp-user\').placeholder=tx.uph;\n  document.getElementById(\'inp-pass\').placeholder=tx.pph;\n  document.getElementById(\'lb-fr\').className=\'lang-btn\'+(l===\'fr\'?\' active\':\'\');\n  document.getElementById(\'lb-en\').className=\'lang-btn\'+(l===\'en\'?\' active\':\'\');\n}\nsetLang(curL);\n</script>\n</body></html>'

APP_HTML = '<style>\n:root{\n  --navy:#020a1a;--blue:#1a3a6e;--camtel:#00d4ff;--b3:#0d2040;\n  --green:#00e676;--g2:#003d1f;--red:#ff4444;--r2:#2d0a0a;\n  --yel:#ffb300;--y2:#2d1f00;\n  --bg:#060d1a;--card:#0d1b35;--bdr:#1e3a5f;--txt:#e2eaff;--muted:#7a9cc0;--lt:#0a1628;\n}\n*{box-sizing:border-box;margin:0;padding:0;}\nbody{font-family:"Segoe UI",system-ui,sans-serif;background:var(--bg);color:var(--txt);font-size:13px;min-height:100vh;}\nbody::before{content:"";position:fixed;top:0;left:0;width:100%;height:100%;z-index:-2;\n  background:radial-gradient(ellipse at 20% 20%,rgba(0,80,160,.3) 0%,transparent 60%),\n    radial-gradient(ellipse at 80% 80%,rgba(0,40,100,.35) 0%,transparent 60%),\n    linear-gradient(180deg,#020810 0%,#060d1a 50%,#030812 100%);}\nbody::after{content:"";position:fixed;top:0;left:0;width:100%;height:100%;z-index:-1;pointer-events:none;\n  background-image:\n    radial-gradient(1px 1px at 12% 7%,rgba(255,255,255,.9) 0%,transparent 100%),\n    radial-gradient(1.5px 1.5px at 30% 14%,rgba(255,255,255,.7) 0%,transparent 100%),\n    radial-gradient(1px 1px at 48% 5%,rgba(200,220,255,.8) 0%,transparent 100%),\n    radial-gradient(2px 2px at 65% 11%,rgba(255,255,255,.6) 0%,transparent 100%),\n    radial-gradient(1px 1px at 82% 7%,rgba(255,255,255,.9) 0%,transparent 100%),\n    radial-gradient(1.5px 1.5px at 92% 20%,rgba(200,220,255,.7) 0%,transparent 100%),\n    radial-gradient(1px 1px at 5% 25%,rgba(255,255,255,.8) 0%,transparent 100%),\n    radial-gradient(1px 1px at 25% 33%,rgba(255,255,255,.5) 0%,transparent 100%),\n    radial-gradient(2px 2px at 72% 28%,rgba(255,255,255,.7) 0%,transparent 100%),\n    radial-gradient(1px 1px at 88% 35%,rgba(200,220,255,.6) 0%,transparent 100%),\n    radial-gradient(1.5px 1.5px at 10% 42%,rgba(255,255,255,.8) 0%,transparent 100%),\n    radial-gradient(1px 1px at 55% 38%,rgba(255,255,255,.6) 0%,transparent 100%),\n    radial-gradient(2px 2px at 78% 55%,rgba(255,255,255,.7) 0%,transparent 100%),\n    radial-gradient(1px 1px at 20% 60%,rgba(255,255,255,.6) 0%,transparent 100%),\n    radial-gradient(1px 1px at 62% 65%,rgba(200,220,255,.8) 0%,transparent 100%);\n  animation:twinkle 6s ease-in-out infinite alternate;}\n@keyframes twinkle{0%{opacity:.5;}50%{opacity:1;}100%{opacity:.6;}}\n.shooting-star{position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:-1;overflow:hidden;}\n.shooting-star::before,.shooting-star::after{content:"";position:absolute;width:2px;height:60px;\n  background:linear-gradient(180deg,transparent,rgba(0,212,255,.8),rgba(255,255,255,1));\n  border-radius:2px;animation:shoot 8s linear infinite;opacity:0;}\n.shooting-star::before{top:10%;left:80%;animation-delay:2s;transform:rotate(45deg);}\n.shooting-star::after{top:30%;left:40%;animation-delay:5s;transform:rotate(45deg);}\n@keyframes shoot{0%{opacity:0;transform:rotate(45deg) translateY(-80px);}10%{opacity:1;}30%{opacity:0;transform:rotate(45deg) translateY(200px);}100%{opacity:0;}}\ninput:not([type=checkbox]):not([type=radio]),select,textarea{background:rgba(4,12,38,.92)!important;color:#c8daf0!important;border:1px solid rgba(0,120,200,.35)!important;border-radius:7px;}\ninput:not([type=checkbox]):focus,select:focus,textarea:focus{border-color:var(--camtel)!important;box-shadow:0 0 0 2px rgba(0,180,255,.15)!important;outline:none!important;}\n.mbox{background:rgba(6,14,42,.97)!important;border:1px solid rgba(0,150,255,.25)!important;color:#c8daf0!important;}\n#g-bar{background:rgba(0,12,40,.75)!important;border-bottom:1px solid rgba(0,120,255,.15)!important;}\nheader{background:linear-gradient(135deg,#020810 0%,#0a1f4e 40%,#0d3060 70%,#003d70 100%);color:#fff;padding:0 14px;height:62px;display:flex;align-items:center;gap:10px;position:sticky;top:0;z-index:200;box-shadow:0 2px 30px rgba(0,180,255,.25);border-bottom:1px solid rgba(0,180,255,.18);}\n.hlogo-svg{width:42px;height:42px;flex-shrink:0;}\n.hbrand h1{font-size:13px;font-weight:800;letter-spacing:.2px;}\n.hbrand p{font-size:9px;opacity:.65;margin-top:1px;}\nnav{display:flex;gap:2px;margin:0 6px;}\nnav button{background:rgba(0,80,180,.2);color:rgba(200,225,255,.75);border:1px solid rgba(0,150,255,.15);padding:5px 10px;border-radius:5px;cursor:pointer;font-size:11px;font-weight:600;white-space:nowrap;transition:all .2s;}\nnav button:hover{background:rgba(0,120,220,.4);color:#fff;border-color:rgba(0,180,255,.35);}nav button.active{background:rgba(0,140,255,.3);color:#00d4ff;border-color:rgba(0,200,255,.5);box-shadow:0 0 10px rgba(0,180,255,.25);}\n.upill{background:rgba(255,255,255,.1);padding:3px 9px;border-radius:20px;font-size:11px;display:flex;align-items:center;gap:5px;white-space:nowrap;}\n.btn{padding:6px 12px;border-radius:7px;border:none;cursor:pointer;font-size:11px;font-weight:700;font-family:inherit;transition:all .15s;display:inline-flex;align-items:center;gap:4px;}\n.bp{background:linear-gradient(135deg,#0d3a7a,#1a5aa0);color:#fff;border-color:#1a5aa0;box-shadow:0 2px 8px rgba(0,80,200,.3);}.bp:hover{background:#00b0e8;}\n.bs{background:#e5e7eb;color:#374151;}.bs:hover{background:#d1d5db;}\n.bd{background:#dc2626;color:#fff;}.bd:hover{background:#b91c1c;}\n.bg2{background:#d1fae5;color:#065f46;border:1px solid #6ee7b7;}\n.bsm{padding:4px 8px;font-size:11px;}\n.bxs{padding:2px 6px;font-size:11px;border-radius:4px;}\n.btn-logout{background:#dc2626;color:#fff;border:none;padding:5px 11px;border-radius:6px;cursor:pointer;font-size:11px;font-weight:700;margin-left:5px;}\n.wrap{max-width:100%;padding:10px 12px;background:transparent;}\n.krow{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:12px;}\n.kpi{background:linear-gradient(135deg,rgba(10,28,60,.95) 0%,rgba(15,35,75,.9) 100%);border:1px solid rgba(0,180,255,.2);border-radius:12px;padding:14px 16px;position:relative;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.5);transition:transform .2s,box-shadow .2s;}\n.kpi:hover{transform:translateY(-2px);box-shadow:0 8px 32px rgba(0,180,255,.2);}\n.kpi::before{content:"";position:absolute;top:0;left:-50%;width:80%;height:1px;background:linear-gradient(90deg,transparent,rgba(0,212,255,.5),transparent);animation:shimmer 3s ease-in-out infinite;}\n@keyframes shimmer{0%{left:-50%;}100%{left:150%;}}\n.kpi label{font-size:9px;text-transform:uppercase;letter-spacing:.1em;color:#7aaccc;font-weight:700;}\n.kpi .val{font-size:20px;font-weight:800;margin-top:4px;font-variant-numeric:tabular-nums;}\n.kpi .sub{font-size:10px;color:#5a8aaa;margin-top:3px;}\n.kpi.kb .val{color:#1f4d8f;}.kpi.kr .val{color:#dc2626;}.kpi.ky .val{color:#d97706;}.kpi.kg .val{color:#16a34a;}\n.gbar{display:flex;align-items:center;gap:8px;margin-bottom:10px;background:rgba(0,12,40,.75);border:1px solid rgba(0,120,255,.15);border-radius:10px;padding:8px 12px;flex-wrap:wrap;}\n.gbar label{font-size:10px;font-weight:700;color:#7aaccc;text-transform:uppercase;}\n.gbar select,.gbar input{padding:5px 8px;border-radius:6px;border:1px solid var(--bdr);font-size:12px;font-family:inherit;}\n.tab-content{display:none;}.tab-content.active{display:block;background:transparent;}\n.card{background:rgba(8,18,45,.88);border:1px solid rgba(0,160,240,.2);border-radius:12px;overflow:hidden;margin-bottom:10px;backdrop-filter:blur(6px);box-shadow:0 4px 24px rgba(0,0,0,.5),inset 0 1px 0 rgba(0,180,255,.05);}\n.ch{padding:10px 14px;border-bottom:1px solid rgba(0,160,240,.2);display:flex;align-items:center;justify-content:space-between;background:linear-gradient(90deg,rgba(0,30,90,.9),rgba(0,20,60,.95));}\n.ch h2{font-size:12px;font-weight:700;flex:1;color:#80ccee;letter-spacing:.02em;}\n.cb{padding:11px;}\n.g2{display:grid;grid-template-columns:1fr 1fr;gap:10px;}\n.g3{display:grid;grid-template-columns:2fr 1fr;gap:10px;}\n.alrt{padding:7px 10px;border-radius:6px;font-size:11px;margin-bottom:7px;border-left:3px solid;}\n.alrt-r{background:#fee2e2;color:#dc2626;border-color:#dc2626;}\n.alrt-y{background:rgba(60,40,0,.3);color:#d97706;border-color:#d97706;}\n.alrt-g{background:rgba(0,80,30,.2);border:1px solid rgba(0,200,80,.35);color:#00e676;}\n.alrt-b{background:#dbeafe;color:#1e40af;border-color:#3b82f6;}\n.prg{height:5px;background:rgba(0,40,100,.4);border-radius:3px;overflow:hidden;margin-top:3px;}\n.prf{height:100%;border-radius:3px;background:linear-gradient(90deg,#0080ff,#00d4ff);box-shadow:0 0 5px rgba(0,200,255,.4);}\n.mbg{display:none;position:fixed;inset:0;background:rgba(10,25,55,.5);z-index:300;align-items:flex-start;justify-content:center;padding-top:30px;overflow-y:auto;}\n.mbg.open{display:flex;}\n.modal{background:rgba(0,15,50,.5);border-radius:13px;width:min(660px,96vw);max-height:88vh;overflow-y:auto;box-shadow:0 20px 60px rgba(0,0,0,.25);margin-bottom:20px;}\n.mh{padding:11px 15px;border-bottom:1px solid var(--bdr);display:flex;align-items:center;justify-content:space-between;background:var(--lt);position:sticky;top:0;}\n.mh h3{font-size:13px;font-weight:700;}\n.mb{padding:15px;}.mf{padding:10px 15px;border-top:1px solid var(--bdr);display:flex;gap:7px;justify-content:flex-end;background:var(--lt);}\n.fr{display:grid;gap:7px;}.fc2{grid-template-columns:1fr 1fr;}.fc3{grid-template-columns:1fr 1fr 1fr;}\n.fld label{display:block;font-size:10px;font-weight:700;color:#80aacc;margin-bottom:3px;text-transform:uppercase;letter-spacing:.04em;}\n.fld input,.fld select,.fld textarea{width:100%;padding:7px 9px;border-radius:6px;border:1.5px solid var(--bdr);font-size:12px;font-family:inherit;}\n.fld input:focus,.fld select:focus,.fld textarea:focus{outline:none;border-color:#1f4d8f;}\n.fld textarea{min-height:50px;resize:vertical;}\n.scan-area{border:2px dashed rgba(0,120,200,.35);border-radius:10px;padding:18px;text-align:center;cursor:pointer;background:rgba(0,20,60,.15);transition:all .2s;}\n.scan-area:hover{border-color:rgba(0,180,255,.5);background:rgba(0,40,100,.2);}\n.cbox-row{display:flex;align-items:center;gap:6px;padding:4px 0;border-bottom:1px solid #f1f5f9;}\n.cbox-row input[type=checkbox]{width:13px;height:13px;accent-color:#1f4d8f;}\n.toast{position:fixed;right:14px;bottom:14px;padding:8px 14px;border-radius:8px;font-size:12px;font-weight:700;z-index:999;display:none;box-shadow:0 4px 14px rgba(0,0,0,.15);}\n\n/* === EXCEL-STYLE TABLE === */\n.tbar{display:flex;align-items:center;gap:6px;flex-wrap:wrap;padding:8px 10px;background:linear-gradient(90deg,#f8fafc,#eff6ff);border:1px solid var(--bdr);border-bottom:none;border-radius:10px 10px 0 0;}\n.tbar input,.tbar select{padding:5px 8px;border-radius:6px;border:1px solid var(--bdr);font-size:11px;font-family:inherit;}\n.excel-wrap{overflow-x:auto;border:2px solid #1e3a8a;border-radius:0 0 8px 8px;}\n.xtbl{width:100%;border-collapse:collapse;font-size:12px;min-width:1350px;}\n\n/* Header colors matching Excel screenshot */\n.xtbl thead tr th{padding:8px 7px;font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:.05em;color:#7abde0;text-align:left;white-space:nowrap;border:1px solid rgba(0,100,200,.2);background:rgba(0,20,65,.95);position:sticky;top:0;z-index:5;}\n.xtbl thead th.th-chk{background:#374151;width:32px;}\n.xtbl thead th.th-date{background:#5b21b6;}\n.xtbl thead th.th-code{background:#3730a3;}\n.xtbl thead th.th-dir{background:#0e7490;}\n.xtbl thead th.th-imp{background:#1e3a8a;min-width:200px;}\n.xtbl thead th.th-nat{background:#166534;}\n.xtbl thead th.th-int{background:#7c2d12;min-width:160px;}\n.xtbl thead th.th-amt{background:#991b1b;text-align:right;}\n.xtbl thead th.th-bcp{background:#065f46;text-align:right;}\n.xtbl thead th.th-cum{background:#4c1d95;text-align:right;}\n.xtbl thead th.th-dis{background:#14532d;text-align:right;}\n.xtbl thead th.th-sta{background:#1e40af;text-align:center;}\n.xtbl thead th.th-act{background:#374151;width:70px;}\n\n/* Row coloring */\n.xtbl tbody tr.row-dep td{background:rgba(150,0,0,.08);}\n.xtbl tbody tr.row-ok td{background:transparent;}\n.xtbl tbody tr.row-pend td{background:rgba(60,40,0,.2);}\n.xtbl tbody tr:hover td{background:rgba(0,60,180,.2) !important;transition:background .08s;}\n.xtbl tbody tr.row-sel td{background:#bfdbfe !important;}\n\n/* Cell styles */\n.xtbl tbody td{padding:6px 7px;border:1px solid rgba(0,50,120,.2);vertical-align:middle;color:#b8d0ec;}\n.xtbl tbody td.tc{text-align:center;}\n.xtbl tbody td.tr{text-align:right;font-family:"Courier New",monospace;font-weight:700;white-space:nowrap;}\n.xtbl tbody td.td-date{color:#5b21b6;font-weight:600;white-space:nowrap;}\n.xtbl tbody td.td-code{font-family:monospace;font-size:10px;color:#3730a3;white-space:nowrap;}\n.xtbl tbody td.td-imp{font-family:monospace;font-size:9px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;}\n.xtbl tbody td.td-int{max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;}\n.xtbl tbody td.td-amt{text-align:right;font-family:"Courier New",monospace;font-weight:800;color:#991b1b;white-space:nowrap;}\n.xtbl tbody td.td-bcp{text-align:right;font-family:"Courier New",monospace;font-weight:700;color:#065f46;white-space:nowrap;}\n.xtbl tbody td.td-cum{text-align:right;font-family:"Courier New",monospace;font-weight:700;color:#7c3aed;white-space:nowrap;}\n.xtbl tbody td.td-dis{text-align:right;font-family:"Courier New",monospace;font-weight:800;white-space:nowrap;}\n\n/* Badges */\n.dir-b{display:inline-block;padding:2px 7px;border-radius:4px;font-size:10px;font-weight:800;background:rgba(0,100,180,.3);color:#60b8e0;border:1px solid rgba(0,130,220,.3);}\n.nat-c{background:rgba(0,80,160,.3);color:#60c8f0;border:1px solid rgba(0,120,220,.3);padding:2px 5px;border-radius:3px;font-size:9px;font-weight:700;}\n.nat-k{background:rgba(120,80,0,.3);color:#ffc040;border:1px solid rgba(200,140,0,.3);padding:2px 5px;border-radius:3px;font-size:9px;font-weight:700;}\n.nat-s{background:rgba(40,0,120,.3);color:#b09fff;border:1px solid rgba(80,40,200,.3);padding:2px 5px;border-radius:3px;font-size:9px;font-weight:700;}\n.sb-ok{background:rgba(0,80,30,.3);color:#00e676;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;border:1px solid #6ee7b7;}\n.sb-dep{background:rgba(120,0,0,.3);color:#ff6060;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;border:1px solid #fca5a5;}\n.sb-pen{background:rgba(60,40,0,.3);color:#92400e;padding:2px 8px;border-radius:4px;font-size:9px;font-weight:700;}\n\n/* Inline new row */\n.new-row td{background:rgba(40,30,0,.2) !important;border:2px solid rgba(180,120,0,.4) !important;}\n.new-row td input,.new-row td select{width:100%;padding:3px 5px;border:1px solid #d1d5db;border-radius:4px;font-size:11px;font-family:inherit;}\n.new-row td input:focus,.new-row td select:focus{outline:none;border-color:#1f4d8f;}\n.new-row td.td-amt input{text-align:right;}\n\n/* Table footer */\n.tfoot{display:flex;justify-content:space-between;align-items:center;padding:6px 10px;background:linear-gradient(90deg,#1e3a8a,#1f4d8f);color:#fff;font-size:11px;font-weight:700;border-radius:0 0 8px 8px;}\n\n/* Budget lines table */\n.bl-tbl{width:100%;border-collapse:collapse;font-size:12px;}\n.bl-tbl thead th{background:linear-gradient(180deg,rgba(0,20,70,.98),rgba(0,30,90,.98));color:#7abde0;padding:8px 8px;font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;white-space:nowrap;border:1px solid rgba(255,255,255,.15);}\n.bl-tbl thead th.tr{text-align:right;}\n.bl-tbl tbody td{padding:7px 8px;border:1px solid #e5e7eb;}\n.bl-tbl tbody tr.bl-ok td{background:rgba(0,40,20,.3);}\n.bl-tbl tbody tr.bl-dep td{background:#fee2e2;}\n.bl-tbl tbody tr:hover td{background:rgba(0,40,120,.3);}\n.bl-tbl td.num{text-align:right;font-family:"Courier New",monospace;font-weight:700;}\n\n/* Users table */\n.u-tbl{width:100%;border-collapse:collapse;font-size:12px;}\n.u-tbl thead th{background:#1f4d8f;color:#fff;padding:8px 8px;font-size:10px;font-weight:700;text-transform:uppercase;white-space:nowrap;}\n.u-tbl tbody td{padding:7px 8px;border-bottom:1px solid #f1f5f9;}\n.u-tbl tbody tr:hover td{background:rgba(0,20,60,.5);}\n\n/* Reports table */\n.r-tbl{width:100%;border-collapse:collapse;font-size:12px;}\n.r-tbl thead th{background:linear-gradient(135deg,#065f46,#16a34a);color:#fff;padding:8px 8px;font-size:9px;font-weight:800;text-transform:uppercase;white-space:nowrap;}\n.r-tbl thead th.tr{text-align:right;}\n.r-tbl tbody td{padding:7px 8px;border-bottom:1px solid #f1f5f9;}\n.r-tbl tbody tr:hover td{background:rgba(0,40,20,.3);}\n.r-tbl td.num{text-align:right;font-family:"Courier New",monospace;font-weight:700;}\n</style>\n</head>\n<body>\n<div class="shooting-star"></div>\n<header>\n  <!-- CAMTEL Logo SVG -->\n  <img src="data:image/png;base64," class="hlogo-svg" alt="CAMTEL" style="object-fit:contain;filter:brightness(0) invert(1);"/>\n  <div class="hbrand">\n    <h1>CAMTEL – Gestion Budgétaire</h1>\n    <p>SAAF / DCF / Contrôle Budgétaire</p>\n  </div>\n  <nav>\n    <button class="active" id="nav-dashboard" onclick="showTab(\'dashboard\')">📊 Dashboard</button>\n    <button id="nav-transactions" onclick="showTab(\'transactions\')">📋 Transactions</button>\n    <button id="nav-budgetlines" onclick="showTab(\'budgetlines\')">📂 Lignes Budget</button>\n    <button id="nav-reports" onclick="showTab(\'reports\')">📈 Rapports</button>\n    <button id="nav-import" onclick="showTab(\'import\')" style="display:none">⬆ Import/Export</button>\n    <button id="nav-planning" onclick="showTab(\'planning\')" style="display:none">📅 Budget Planning</button>\n    <button id="nav-users" onclick="showTab(\'users\')" style="display:none">👥 Utilisateurs</button>\n  </nav>\n  <div class="upill">\n    <span id="uname">—</span>\n    <span id="urole" style="background:rgba(0,176,232,.35);padding:2px 7px;border-radius:10px;font-size:9px;font-weight:800;">—</span>\n  </div>\n  <button id="lang-btn" class="btn-logout" style="background:#0891b2;margin-right:4px" onclick="toggleLang()">🌐 EN</button>\n  <button class="btn-logout" onclick="logout()">Déconnexion</button>\n</header>\n\n<div class="wrap" style="background:transparent;">\n  <div class="gbar">\n    <label style="color:#7aaccc;font-weight:700;font-size:11px;letter-spacing:.05em;">YEAR :</label>\n    <select id="g-year" style="font-weight:800;background:rgba(0,20,70,.9);color:#00d4ff;border:1px solid rgba(0,180,255,.3);padding:5px 8px;border-radius:6px;" onchange="onYearChange()"></select>\n    <label style="color:#7aaccc;font-weight:700;font-size:11px;letter-spacing:.05em;">DIRECTION :</label>\n    <select id="g-dir" style="min-width:140px;background:rgba(0,20,70,.9);color:#c8daf0;border:1px solid rgba(0,180,255,.3);padding:5px 8px;border-radius:6px;" onchange="onDirChange()"></select>\n    <span id="last-upd" style="font-size:10px;color:#5a8aaa;margin-left:auto;font-variant-numeric:tabular-nums;"></span>\n    <button style="background:rgba(0,100,180,.3);color:#80c8f0;border:1px solid rgba(0,150,255,.3);padding:5px 12px;border-radius:6px;cursor:pointer;font-size:11px;font-weight:700;" onclick="refreshAll()">↻ Refresh</button>\n  </div>\n\n  <div class="krow">\n    <div class="kpi kb"><label>Budget CP Total</label><div class="val" id="kpi-bud">—</div><div class="sub" id="kpi-bud-s"></div></div>\n    <div class="kpi kr"><label>Cumul Engagé</label><div class="val" id="kpi-eng">—</div><div class="sub" id="kpi-eng-s"></div></div>\n    <div class="kpi ky"><label>En Attente</label><div class="val" id="kpi-pend">—</div><div class="sub" id="kpi-pend-s"></div></div>\n    <div class="kpi kg"><label>Disponible Après</label><div class="val" id="kpi-dispo">—</div><div class="sub" id="kpi-dispo-s"></div></div>\n  </div>\n  <div id="alerts-row"></div>\n\n  <!-- DASHBOARD -->\n  <div id="tab-dashboard" class="tab-content active">\n    <!-- CAMTEL HERO BANNER -->\n    <div style="position:relative;overflow:hidden;border-radius:14px;margin-bottom:14px;height:130px;background:linear-gradient(135deg,#020810 0%,#0a1f4e 40%,#0d3566 70%,#003d70 100%);border:1px solid rgba(0,180,255,.25);box-shadow:0 6px 40px rgba(0,0,0,.6);">\n      <div style="position:absolute;inset:0;opacity:.07;background-image:linear-gradient(rgba(0,180,255,.5) 1px,transparent 1px),linear-gradient(90deg,rgba(0,180,255,.5) 1px,transparent 1px);background-size:40px 40px;animation:gridMove 20s linear infinite;"></div>\n      <style>@keyframes gridMove{from{background-position:0 0;}to{background-position:40px 40px;}}</style>\n      <div style="position:absolute;top:-30px;left:10%;width:180px;height:180px;background:radial-gradient(circle,rgba(0,180,255,.15) 0%,transparent 70%);border-radius:50%;animation:pulseOrb 4s ease-in-out infinite;"></div>\n      <div style="position:absolute;top:-20px;right:15%;width:140px;height:140px;background:radial-gradient(circle,rgba(0,100,200,.12) 0%,transparent 70%);border-radius:50%;animation:pulseOrb 4s ease-in-out infinite 2s;"></div>\n      <style>@keyframes pulseOrb{0%,100%{transform:scale(1);opacity:.8;}50%{transform:scale(1.15);opacity:1;}}</style>\n      <div style="position:absolute;right:0;top:0;height:100%;width:55%;overflow:hidden;mask-image:linear-gradient(90deg,transparent,black 15%,black 85%,transparent);-webkit-mask-image:linear-gradient(90deg,transparent,black 15%,black 85%,transparent);">\n        <div style="display:flex;gap:16px;align-items:center;animation:slideImg 22s linear infinite;padding:0 8px;">\n          <div style="min-width:120px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 12px rgba(0,180,255,0.6));"><svg viewBox="0 0 80 120" fill="none" xmlns="http://www.w3.org/2000/svg" width="70" height="110">\n  <line x1="40" y1="5" x2="40" y2="110" stroke="#00d4ff" stroke-width="2"/>\n  <line x1="40" y1="5" x2="10" y2="110" stroke="#00a0cc" stroke-width="1.5"/>\n  <line x1="40" y1="5" x2="70" y2="110" stroke="#00a0cc" stroke-width="1.5"/>\n  <line x1="15" y1="95" x2="65" y2="95" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="20" y1="75" x2="60" y2="75" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="25" y1="55" x2="55" y2="55" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="30" y1="35" x2="50" y2="35" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="15" y1="95" x2="25" y2="75" stroke="#0070aa" stroke-width="1"/>\n  <line x1="65" y1="95" x2="55" y2="75" stroke="#0070aa" stroke-width="1"/>\n  <line x1="20" y1="75" x2="28" y2="55" stroke="#0070aa" stroke-width="1"/>\n  <line x1="60" y1="75" x2="52" y2="55" stroke="#0070aa" stroke-width="1"/>\n  <rect x="36" y="2" width="8" height="16" fill="#00d4ff" opacity="0.9"/>\n  <rect x="34" y="10" width="12" height="3" fill="#00d4ff" opacity="0.7"/>\n  <rect x="34" y="16" width="12" height="3" fill="#00d4ff" opacity="0.7"/>\n  <circle cx="40" cy="2" r="3" fill="#ff4444"/>\n</svg></div>\n          <div style="min-width:120px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 10px rgba(0,180,255,0.5));"><svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" width="80" height="80">\n  <ellipse cx="35" cy="55" rx="28" ry="20" fill="none" stroke="#00d4ff" stroke-width="2" transform="rotate(-30 35 55)"/>\n  <ellipse cx="35" cy="55" rx="28" ry="20" fill="rgba(0,180,255,0.08)" transform="rotate(-30 35 55)"/>\n  <line x1="15" y1="68" x2="55" y2="42" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="18" y1="62" x2="52" y2="48" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="21" y1="56" x2="49" y2="54" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="35" y1="55" x2="62" y2="30" stroke="#00d4ff" stroke-width="2"/>\n  <circle cx="64" cy="28" r="6" fill="rgba(0,180,255,0.2)" stroke="#00d4ff" stroke-width="1.5"/>\n  <circle cx="64" cy="28" r="2" fill="#00d4ff"/>\n  <rect x="56" y="22" width="6" height="12" rx="1" fill="rgba(0,120,200,0.5)" stroke="#0080cc" stroke-width="1"/>\n  <rect x="64" y="22" width="6" height="12" rx="1" fill="rgba(0,120,200,0.5)" stroke="#0080cc" stroke-width="1"/>\n</svg></div>\n          <div style="min-width:100px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 10px rgba(0,100,200,0.5));"><svg viewBox="0 0 70 110" fill="none" xmlns="http://www.w3.org/2000/svg" width="55" height="100">\n  <rect x="10" y="20" width="50" height="88" fill="rgba(0,40,100,0.6)" stroke="#0080cc" stroke-width="1"/>\n  <rect x="10" y="20" width="50" height="88" fill="url(#bgrad)"/>\n  <defs><linearGradient id="bgrad" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="rgba(0,60,140,0.8)"/><stop offset="100%" stop-color="rgba(0,100,180,0.4)"/></linearGradient></defs>\n  <rect x="15" y="30" width="8" height="8" fill="rgba(0,180,255,0.4)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="28" y="30" width="8" height="8" fill="rgba(0,180,255,0.4)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="41" y="30" width="8" height="8" fill="rgba(0,180,255,0.7)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="15" y="45" width="8" height="8" fill="rgba(0,180,255,0.6)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="28" y="45" width="8" height="8" fill="rgba(0,180,255,0.3)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="41" y="45" width="8" height="8" fill="rgba(0,180,255,0.5)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="15" y="60" width="8" height="8" fill="rgba(0,180,255,0.5)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="28" y="60" width="8" height="8" fill="rgba(0,180,255,0.7)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="41" y="60" width="8" height="8" fill="rgba(0,180,255,0.3)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="15" y="75" width="8" height="8" fill="rgba(0,180,255,0.6)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="28" y="75" width="8" height="8" fill="rgba(0,180,255,0.4)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="41" y="75" width="8" height="8" fill="rgba(0,180,255,0.6)" stroke="#00a0cc" stroke-width="0.5"/>\n  <rect x="22" y="90" width="16" height="18" fill="rgba(0,80,160,0.5)" stroke="#0080cc" stroke-width="0.5"/>\n  <rect x="30" y="5" width="4" height="18" fill="#00d4ff" opacity="0.8"/>\n  <circle cx="32" cy="4" r="2" fill="#ff4444"/>\n</svg></div>\n          <div style="min-width:120px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 12px rgba(0,180,255,0.5));"><svg viewBox="0 0 90 90" fill="none" xmlns="http://www.w3.org/2000/svg" width="75" height="75">\n  <circle cx="45" cy="45" r="38" stroke="#00d4ff" stroke-width="1.5" fill="rgba(0,60,120,0.2)"/>\n  <ellipse cx="45" cy="45" rx="18" ry="38" stroke="#0080cc" stroke-width="1" fill="none"/>\n  <ellipse cx="45" cy="45" rx="38" ry="15" stroke="#0080cc" stroke-width="1" fill="none"/>\n  <line x1="7" y1="45" x2="83" y2="45" stroke="#0080cc" stroke-width="1" opacity="0.6"/>\n  <line x1="10" y1="28" x2="80" y2="28" stroke="#0080cc" stroke-width="1" opacity="0.4"/>\n  <line x1="10" y1="62" x2="80" y2="62" stroke="#0080cc" stroke-width="1" opacity="0.4"/>\n  <circle cx="45" cy="45" r="38" fill="none" stroke="rgba(0,180,255,0.15)" stroke-width="8"/>\n  <circle cx="62" cy="28" r="5" fill="rgba(255,180,0,0.6)" stroke="#ffb300" stroke-width="1"/>\n  <circle cx="28" cy="52" r="4" fill="rgba(0,230,118,0.5)" stroke="#00e676" stroke-width="1"/>\n  <circle cx="55" cy="58" r="3" fill="rgba(0,212,255,0.6)" stroke="#00d4ff" stroke-width="1"/>\n  <line x1="62" y1="28" x2="28" y2="52" stroke="#ffb300" stroke-width="1" stroke-dasharray="3,3" opacity="0.6"/>\n  <line x1="28" y1="52" x2="55" y2="58" stroke="#00e676" stroke-width="1" stroke-dasharray="3,3" opacity="0.6"/>\n</svg></div>\n          <div style="min-width:120px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 12px rgba(0,180,255,0.6));"><svg viewBox="0 0 80 120" fill="none" xmlns="http://www.w3.org/2000/svg" width="70" height="110">\n  <line x1="40" y1="5" x2="40" y2="110" stroke="#00d4ff" stroke-width="2"/>\n  <line x1="40" y1="5" x2="10" y2="110" stroke="#00a0cc" stroke-width="1.5"/>\n  <line x1="40" y1="5" x2="70" y2="110" stroke="#00a0cc" stroke-width="1.5"/>\n  <line x1="15" y1="95" x2="65" y2="95" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="20" y1="75" x2="60" y2="75" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="25" y1="55" x2="55" y2="55" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="30" y1="35" x2="50" y2="35" stroke="#0080aa" stroke-width="1.5"/>\n  <line x1="15" y1="95" x2="25" y2="75" stroke="#0070aa" stroke-width="1"/>\n  <line x1="65" y1="95" x2="55" y2="75" stroke="#0070aa" stroke-width="1"/>\n  <line x1="20" y1="75" x2="28" y2="55" stroke="#0070aa" stroke-width="1"/>\n  <line x1="60" y1="75" x2="52" y2="55" stroke="#0070aa" stroke-width="1"/>\n  <rect x="36" y="2" width="8" height="16" fill="#00d4ff" opacity="0.9"/>\n  <rect x="34" y="10" width="12" height="3" fill="#00d4ff" opacity="0.7"/>\n  <rect x="34" y="16" width="12" height="3" fill="#00d4ff" opacity="0.7"/>\n  <circle cx="40" cy="2" r="3" fill="#ff4444"/>\n</svg></div>\n          <div style="min-width:120px;height:130px;display:flex;align-items:center;justify-content:center;filter:drop-shadow(0 0 10px rgba(0,180,255,0.5));"><svg viewBox="0 0 100 100" fill="none" xmlns="http://www.w3.org/2000/svg" width="80" height="80">\n  <ellipse cx="35" cy="55" rx="28" ry="20" fill="none" stroke="#00d4ff" stroke-width="2" transform="rotate(-30 35 55)"/>\n  <ellipse cx="35" cy="55" rx="28" ry="20" fill="rgba(0,180,255,0.08)" transform="rotate(-30 35 55)"/>\n  <line x1="15" y1="68" x2="55" y2="42" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="18" y1="62" x2="52" y2="48" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="21" y1="56" x2="49" y2="54" stroke="#00a0cc" stroke-width="1" opacity="0.5"/>\n  <line x1="35" y1="55" x2="62" y2="30" stroke="#00d4ff" stroke-width="2"/>\n  <circle cx="64" cy="28" r="6" fill="rgba(0,180,255,0.2)" stroke="#00d4ff" stroke-width="1.5"/>\n  <circle cx="64" cy="28" r="2" fill="#00d4ff"/>\n  <rect x="56" y="22" width="6" height="12" rx="1" fill="rgba(0,120,200,0.5)" stroke="#0080cc" stroke-width="1"/>\n  <rect x="64" y="22" width="6" height="12" rx="1" fill="rgba(0,120,200,0.5)" stroke="#0080cc" stroke-width="1"/>\n</svg></div>\n        </div>\n      </div>\n      <style>@keyframes slideImg{from{transform:translateX(0);}to{transform:translateX(-50%);}}</style>\n      <div style="position:absolute;left:0;top:0;height:100%;padding:18px 24px;display:flex;flex-direction:column;justify-content:center;z-index:2;">\n        <div style="display:flex;align-items:center;gap:10px;margin-bottom:6px;">\n          <div style="width:3px;height:32px;background:linear-gradient(180deg,#00d4ff,#0077ff);border-radius:2px;box-shadow:0 0 8px #00d4ff;"></div>\n          <div>\n            <div style="font-size:18px;font-weight:900;color:#fff;letter-spacing:.05em;text-shadow:0 0 20px rgba(0,212,255,.5);">CAMTEL</div>\n            <div style="font-size:10px;color:#00d4ff;font-weight:600;letter-spacing:.15em;text-transform:uppercase;">Budget Management System</div>\n          </div>\n        </div>\n        <div id="dash-ticker" style="font-size:11px;color:rgba(200,230,255,.8);max-width:380px;line-height:1.5;min-height:36px;border-left:2px solid rgba(0,180,255,.3);padding-left:10px;transition:opacity .5s;"></div>\n      </div>\n      <div style="position:absolute;bottom:10px;right:14px;font-size:10px;color:rgba(0,200,255,.7);font-weight:700;letter-spacing:.06em;" id="hero-clock"></div>\n    </div>\n\n    <div class="g3" style="margin-bottom:10px">\n      <div class="card"><div class="ch"><h2>📊 Engagements par direction</h2></div><div class="cb"><canvas id="ch-dir" height="190"></canvas></div></div>\n      <div class="card"><div class="ch"><h2>📈 Tendance mensuelle</h2></div><div class="cb"><canvas id="ch-mo" height="190"></canvas></div></div>\n    </div>\n    <div class="card"><div class="ch"><h2>🎯 Taux d\'utilisation — toutes directions</h2></div><div class="cb" id="dir-prog"></div></div>\n    <div class="card" style="margin-top:10px">\n      <div class="ch"><h2>🕐 Dernières transactions</h2></div>\n      <div id="tx-all-years-banner" style="display:none;background:rgba(0,50,150,.2);border:1px solid rgba(0,120,255,.35);border-radius:6px;padding:6px 12px;margin-bottom:6px;font-size:11px;font-weight:700;color:#80b8f0"></div>\n    <div style="overflow-x:auto">\n        <table class="xtbl" style="min-width:900px">\n          <thead><tr>\n            <th class="th-chk"></th><th class="th-date">Date</th><th class="th-code">Code/Réf</th>\n            <th class="th-dir">Direction</th><th class="th-imp">Imputation</th><th class="th-nat">Nature</th>\n            <th class="th-int">Intitulé</th><th class="th-amt">Montant</th>\n            <th class="th-bcp">Budget CP</th><th class="th-cum">Cumul Engagé</th>\n            <th class="th-dis">Disponible Après</th><th class="th-sta">Statut Budget</th><th class="th-act"></th>\n          </tr></thead>\n          <tbody id="rec-rows"></tbody>\n        </table>\n      </div>\n    </div>\n  </div>\n\n  <!-- TRANSACTIONS -->\n  <div id="tab-transactions" class="tab-content">\n    <!-- Period Search Bar -->\n    <div style="background:rgba(0,40,100,.3);border:1.5px solid rgba(0,180,255,.4);border-radius:8px;padding:8px 12px;margin-bottom:8px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">\n      <span style="font-weight:800;color:#0369a1;font-size:11px">&#128269; RECHERCHE PAR P&Eacute;RIODE / SEARCH BY PERIOD</span>\n      <select id="tx-s-month" style="padding:5px 8px;font-weight:700;border:1.5px solid #0ea5e9;border-radius:4px;color:#0369a1;cursor:pointer">\n        <option value="">&#8212; Mois / Month &#8212;</option>\n        <option value="1">Janvier / January</option><option value="2">F&#233;vrier / February</option>\n        <option value="3">Mars / March</option><option value="4">Avril / April</option>\n        <option value="5">Mai / May</option><option value="6">Juin / June</option>\n        <option value="7">Juillet / July</option><option value="8">Ao&#251;t / August</option>\n        <option value="9">Septembre / September</option><option value="10">Octobre / October</option>\n        <option value="11">Novembre / November</option><option value="12">D&#233;cembre / December</option>\n      </select>\n      <select id="tx-s-year" style="padding:5px 8px;font-weight:700;border:1.5px solid #0ea5e9;border-radius:4px;color:#0369a1;cursor:pointer">\n        <option value="">&#8212; Ann&#233;e / Year &#8212;</option>\n      </select>\n      <button onclick="searchByPeriod()" style="padding:5px 18px;background:#0369a1;color:#fff;border:none;border-radius:5px;font-weight:800;cursor:pointer;font-size:12px">&#128269; RECHERCHER / SEARCH</button>\n      <button onclick="clearPeriodSearch()" style="padding:5px 12px;background:#64748b;color:#fff;border:none;border-radius:5px;font-weight:700;cursor:pointer">&#10005; Effacer</button>\n      <span id="tx-search-info" style="font-size:10px;color:#0369a1;font-style:italic;font-weight:700"></span>\n    </div>\n    <div class="tbar">\n      <select id="tx-f-dir" onchange="loadTx()" style="min-width:100px"><option value="">Toutes directions</option></select>\n      <select id="tx-f-status" onchange="loadTx()">\n        <option value="">Tous statuts</option><option value="validated">Validé</option><option value="pending">Brouillon</option>\n      </select>\n      <select id="tx-f-statbud" onchange="loadTx()">\n        <option value="">Tous statuts budget</option><option value="NORMAL">Normal (OK)</option><option value="DEPASSEMENT">Dépassement</option>\n      </select>\n      <input id="tx-q" placeholder="🔍 Réf, intitulé, imputation..."/>\n      <select id="tx-f-year" onchange="this._userPicked=true;loadTx()" style="font-weight:700;border:1px solid rgba(0,180,255,.4);color:#00d4ff;background:rgba(0,20,60,.9)"><option value="">Toutes années / All years</option>\n        <option value="">Toutes années</option>\n      </select>\n      <div style="margin-left:auto;display:flex;gap:5px;flex-wrap:wrap;">\n        <button class="btn bp bsm viewer-hide" onclick="addNewRow()">➕ Nouvelle ligne</button>\n        <button class="btn bg2 bsm" id="print-sel-btn" onclick="printSelected()" style="display:none">🖨 Imprimer sélection</button>\n        <button class="btn bs bsm" onclick="exportTx()">⬇ CSV</button>\n      </div>\n    </div>\n    <div id="tx-sel-info" style="padding:5px 10px;background:#dbeafe;font-size:11px;color:#1e40af;border:1px solid #93c5fd;border-top:none;display:none">\n      <strong id="tx-sel-count">0</strong> sélectionnée(s) — 🖨 pour imprimer (2 max par page A4)\n    </div>\n    <div class="excel-wrap">\n      <table class="xtbl" id="tx-table">\n        <thead><tr>\n          <th class="th-chk"><input type="checkbox" id="sel-all" onchange="toggleSelAll(this)" style="accent-color:#fff"/></th>\n          <th class="th-date">DATE DE RÉCEPTION</th>\n          <th class="th-code">CODE / RÉF</th>\n          <th class="th-dir">DIRECTION</th>\n          <th class="th-imp">IMPUTATION COMPTABLE</th>\n          <th class="th-nat">NATURE</th><th style="min-width:75px;background:#0e7490">D&Eacute;SIGNATION</th>\n          <th class="th-int">INTITULÉ DE LA COMMANDE</th>\n          <th class="th-amt">MONTANT</th>\n          <th class="th-bcp">BUDGET CP</th>\n          <th class="th-cum">CUMUL ENGAGÉ</th>\n          <th class="th-dis">DISPONIBLE APRÈS</th>\n          <th class="th-sta">STATUT BUDGET</th>\n          <th class="th-act">ACTIONS</th>\n        </tr></thead>\n        <tbody id="tx-rows"></tbody>\n      </table>\n    </div>\n    <div id="tx-empty" style="padding:28px;text-align:center;color:var(--muted);display:none">Aucune transaction. Cliquez <strong>➕ Nouvelle ligne</strong> pour ajouter.</div>\n    <div class="tfoot" id="tx-foot" style="display:none">\n      <span id="tx-foot-count">0 transaction(s)</span>\n      <span id="tx-foot-total" style="font-family:\'Courier New\',monospace;font-size:13px"></span>\n    </div>\n  </div>\n\n  <!-- BUDGET LINES -->\n  <div id="tab-budgetlines" class="tab-content">\n    <div class="tbar">\n      <select id="bl-f-dir" onchange="loadBL()" style="min-width:100px"><option value="">Toutes directions</option></select>\n      <input id="bl-q" placeholder="🔍 Imputation, libellé..."/>\n      <div style="margin-left:auto;display:flex;gap:5px">\n        <button class="btn bp bsm admin-only" onclick="openBLModal()">+ Nouvelle ligne</button>\n        <button class="btn bs bsm" onclick="window.open(\'/api/export/template-budget-lines\',\'_blank\')">⬇ Template</button>\n      </div>\n    </div>\n    <div style="overflow-x:auto;border:2px solid #1e3a8a;border-top:none;border-radius:0 0 8px 8px">\n      <table class="bl-tbl">\n        <thead><tr>\n          <th>Direction</th><th>Imputation comptable</th><th>Libellé</th><th>Nature</th>\n          <th class="tr">Budget CP</th><th class="tr">Cumul Engagé</th><th class="tr">Disponible Après</th>\n          <th>Taux</th><th>Statut</th><th class="admin-only"></th>\n        </tr></thead>\n        <tbody id="bl-rows"></tbody>\n      </table>\n    </div>\n    <div id="bl-empty" style="padding:28px;text-align:center;color:var(--muted);display:none">Aucune ligne budgétaire. Importez via ⬆ Import/Export.</div>\n  </div>\n\n  <!-- REPORTS -->\n  <div id="tab-reports" class="tab-content">\n    <!-- KPI STRIP -->\n    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:12px">\n      <div class="card" style="padding:14px 16px;margin-bottom:0">\n        <div style="font-size:9px;font-weight:700;color:#7aaccc;letter-spacing:.1em;text-transform:uppercase">TOTAL CP BUDGET</div>\n        <div id="rp-kpi-budget" style="font-size:24px;font-weight:800;color:#00d4ff;margin-top:4px">0</div>\n      </div>\n      <div class="card" style="padding:14px 16px;margin-bottom:0">\n        <div style="font-size:9px;font-weight:700;color:#7aaccc;letter-spacing:.1em;text-transform:uppercase">TOTAL COMMITTED</div>\n        <div id="rp-kpi-engage" style="font-size:24px;font-weight:800;color:#ff6b6b;margin-top:4px">0</div>\n        <div id="rp-kpi-txcount" style="font-size:10px;color:#5a8aaa;margin-top:2px">0 transaction(s) validated</div>\n      </div>\n      <div class="card" style="padding:14px 16px;margin-bottom:0">\n        <div style="font-size:9px;font-weight:700;color:#7aaccc;letter-spacing:.1em;text-transform:uppercase">ON HOLD</div>\n        <div id="rp-kpi-pending" style="font-size:24px;font-weight:800;color:#ffb300;margin-top:4px">0</div>\n        <div id="rp-kpi-draftcount" style="font-size:10px;color:#5a8aaa;margin-top:2px">0 draft(s)</div>\n      </div>\n      <div class="card" style="padding:14px 16px;margin-bottom:0">\n        <div style="font-size:9px;font-weight:700;color:#7aaccc;letter-spacing:.1em;text-transform:uppercase">AVAILABLE AFTER</div>\n        <div id="rp-kpi-dispo" style="font-size:24px;font-weight:800;color:#00e676;margin-top:4px">0</div>\n        <div id="rp-kpi-pct" style="font-size:10px;color:#5a8aaa;margin-top:2px">0% of the budget committed</div>\n      </div>\n    </div>\n    <!-- MONTHLY REPORT + ANNUAL SUMMARY -->\n    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px">\n      <div class="card">\n        <div class="ch"><h2>📊 Monthly report</h2></div>\n        <div class="cb">\n          <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px">\n            <div class="fld">\n              <label style="text-transform:uppercase;letter-spacing:.08em">YEAR</label>\n              <select id="rp-year" style="width:100%;padding:8px;border-radius:6px;font-size:13px;font-weight:600"></select>\n            </div>\n            <div class="fld">\n              <label style="text-transform:uppercase;letter-spacing:.08em">MONTH</label>\n              <select id="rp-month" style="width:100%;padding:8px;border-radius:6px;font-size:13px">\n                <option value="1">January / Janvier</option>\n                <option value="2">February / Février</option>\n                <option value="3">March / Mars</option>\n                <option value="4">April / Avril</option>\n                <option value="5">May / Mai</option>\n                <option value="6">June / Juin</option>\n                <option value="7">July / Juillet</option>\n                <option value="8">August / Août</option>\n                <option value="9">September / Septembre</option>\n                <option value="10">October / Octobre</option>\n                <option value="11">November / Novembre</option>\n                <option value="12">December / Décembre</option>\n                <option value="0" style="font-weight:800;color:#00d4ff;border-top:2px solid #1a4080">── Full Year (All 12 Months) ──</option>\n              </select>\n            </div>\n          </div>\n          <div style="display:flex;gap:8px;margin-bottom:12px">\n            <button class="btn bp" style="padding:8px 16px;display:flex;align-items:center;gap:5px" onclick="downloadReport()">📥 CSV</button>\n            <button class="btn bs" style="padding:8px 16px;display:flex;align-items:center;gap:5px" onclick="loadReports()">📊 Show</button>\n          </div>\n          <div class="alrt alrt-b">📋 Monthly report for DCF Director and Deputy Budget Director.<br><strong>Select "Full Year"</strong> for complete annual report with all imported transactions.</div>\n        </div>\n      </div>\n      <div class="card">\n        <div class="ch"><h2>📈 Annual summary</h2></div>\n        <div class="cb" id="rp-summary">\n          <div style="padding:20px;text-align:center;color:#5a8aaa;font-size:12px">\n            <div style="font-size:32px;margin-bottom:8px">📊</div>\n            Select year &amp; month then click <strong>Show</strong>\n          </div>\n        </div>\n      </div>\n    </div>\n    <!-- MONTHLY BREAKDOWN (Full Year) -->\n    <div id="rp-monthly-breakdown" class="card" style="display:none;margin-bottom:12px">\n      <div class="ch" style="background:linear-gradient(90deg,rgba(0,60,20,.9),rgba(0,40,15,.95))"><h2 style="color:#00e676">📅 Monthly Breakdown — <span id="rp-breakdown-year">—</span></h2></div>\n      <div style="overflow-x:auto">\n        <table class="r-tbl">\n          <thead><tr>\n            <th>Month</th><th class="tr">Transactions</th><th class="tr">Committed (Validated)</th>\n            <th class="tr">On Hold (Pending)</th><th class="tr">Cumulative</th><th>% of Budget</th>\n          </tr></thead>\n          <tbody id="rp-month-rows"></tbody>\n        </table>\n      </div>\n    </div>\n    <!-- DIRECTION TABLE -->\n    <div class="card">\n      <div class="ch" style="background:linear-gradient(90deg,rgba(0,60,20,.9),rgba(0,40,15,.95))">\n        <h2 style="color:#00e676">Followed by direction — <span id="rp-year-label" style="color:#00e676">—</span></h2>\n      </div>\n      <div style="overflow-x:auto"><table class="r-tbl">\n        <thead style="background:rgba(0,60,20,.9)">\n          <tr>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:center">DIRECTION</th>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:center">CP BUDGET</th>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:center">TOTAL COMMITMENTS</th>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:right">AVAILABLE</th>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:center">RATE %</th>\n            <th style="background:rgba(0,80,30,.95);color:#00e676;text-align:center">STATUS</th>\n          </tr>\n        </thead>\n        <tbody id="rp-dir-rows">\n          <tr><td colspan="6" style="text-align:center;padding:20px;color:#5a8aaa">Click Show to load data</td></tr>\n        </tbody>\n      </table></div>\n    </div>\n  </div>\n\n  <!-- IMPORT/EXPORT -->\n  <div id="tab-import" class="tab-content">\n    <!-- KPI mini-strip for context -->\n    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px">\n      <div class="kpi kb"><label>Budget CP Total</label><div class="val" id="kpi-bud-imp">—</div><div class="sub" id="kpi-bud-s-imp"></div></div>\n      <div class="kpi kr"><label>Cumul Engagé</label><div class="val" id="kpi-eng2">—</div><div class="sub" id="kpi-eng-s2"></div></div>\n      <div class="kpi ky"><label>En Attente</label><div class="val" id="kpi-pend2">—</div><div class="sub" id="kpi-pend-s2"></div></div>\n      <div class="kpi kg"><label>Disponible Après</label><div class="val" id="kpi-dispo2">—</div><div class="sub" id="kpi-dispo-s2"></div></div>\n    </div>\n\n    <div class="g2" style="margin-bottom:10px">\n      <!-- IMPORT TRANSACTIONS -->\n      <div class="card">\n        <div class="ch" style="background:linear-gradient(90deg,rgba(20,50,10,.9),rgba(10,40,5,.95))">\n          <h2 style="color:#00e676">⬆ Import transactions (CSV)</h2>\n        </div>\n        <div class="cb">\n          <div class="alrt alrt-b" style="margin-bottom:9px;font-size:10px">\n            <strong>✅ Compatible with your CAMTEL template CSV</strong><br>\n            <span style="color:#00e676">Columns auto-detected:</span> DATE ENGAGEMENT · DIRECTION · INTITULE DE LA COMMANDE · LIBELLE · NATURE DE LA DEPENSE · IMPUTATION COMPTABLE · MONTANT<br>\n            <span style="opacity:.75">💡 The title row "SITUATION DES ENGAGEMENTS..." is automatically skipped. Amounts like "291,959,762" are parsed correctly.</span>\n          </div>\n          <div class="fld" style="margin-bottom:8px">\n            <label>YEAR *</label>\n            <input type="number" id="imp-tx-year" value="2025" style="font-weight:700;font-size:14px;width:100%;padding:8px;"/>\n          </div>\n          <div class="scan-area" onclick="document.getElementById(\'imp-tx-file\').click()" id="imp-tx-area"\n            style="border:2px dashed rgba(0,180,100,.4);border-radius:10px;padding:20px;text-align:center;cursor:pointer;background:rgba(0,80,20,.1);transition:all .2s;"\n            onmouseover="this.style.borderColor=\'rgba(0,230,118,.6)\';this.style.background=\'rgba(0,80,20,.2)\'"\n            onmouseout="this.style.borderColor=\'rgba(0,180,100,.4)\';this.style.background=\'rgba(0,80,20,.1)\'">\n            <div style="font-size:32px;margin-bottom:6px">📂</div>\n            <div style="font-size:12px;font-weight:700;color:#80d4b0">Click to choose CSV file</div>\n            <div style="font-size:10px;color:#5a8aaa;margin-top:4px">Supports UTF-8, Latin-1, CSV formats</div>\n            <div id="imp-tx-fname" style="margin-top:6px;font-size:11px;color:#00e676;font-weight:700"></div>\n          </div>\n          <input type="file" id="imp-tx-file" accept=".csv,.txt" style="display:none" onchange="onFileSel(this,\'imp-tx-fname\',\'imp-tx-area\')"/>\n          <div style="margin-top:10px;display:flex;gap:6px;flex-wrap:wrap">\n            <button class="btn bp" style="padding:9px 18px;font-size:12px" onclick="importTx()">⬆ Import</button>\n            <button class="btn bs" style="padding:9px 14px;font-size:12px" onclick="window.open(\'/api/export/template-transactions\',\'_blank\')">⬇ Template</button>\n          </div>\n          <div id="imp-tx-result" style="margin-top:8px"></div>\n        </div>\n      </div>\n\n      <!-- IMPORT BUDGET LINES -->\n      <div class="card">\n        <div class="ch" style="background:linear-gradient(90deg,rgba(0,40,80,.9),rgba(0,25,60,.95))">\n          <h2 style="color:#00d4ff">⬆ Import budget lines (CSV)</h2>\n        </div>\n        <div class="cb">\n          <div class="alrt alrt-b" style="margin-bottom:9px;font-size:10px">\n            <strong>Columns:</strong> YEAR · DIRECTION · ACCOUNTING ENTRY · DESCRIPTION · NATURE · BUDGET CP (FCFA)<br>\n            <span style="opacity:.8">For budget 2026, 2027...</span>\n          </div>\n          <div class="scan-area" onclick="document.getElementById(\'imp-bl-file\').click()" id="imp-bl-area"\n            style="border:2px dashed rgba(0,120,255,.3);border-radius:10px;padding:20px;text-align:center;cursor:pointer;background:rgba(0,40,100,.1);transition:all .2s;"\n            onmouseover="this.style.borderColor=\'rgba(0,180,255,.5)\';this.style.background=\'rgba(0,40,100,.2)\'"\n            onmouseout="this.style.borderColor=\'rgba(0,120,255,.3)\';this.style.background=\'rgba(0,40,100,.1)\'">\n            <div style="font-size:32px;margin-bottom:6px">📊</div>\n            <div style="font-size:12px;font-weight:700;color:#80b8e0">Click to choose budget CSV file</div>\n            <div style="font-size:10px;color:#5a8aaa;margin-top:4px">Supports UTF-8, Latin-1, CSV formats</div>\n            <div id="imp-bl-fname" style="margin-top:6px;font-size:11px;color:#00d4ff;font-weight:700"></div>\n          </div>\n          <input type="file" id="imp-bl-file" accept=".csv,.txt" style="display:none" onchange="onFileSel(this,\'imp-bl-fname\',\'imp-bl-area\')"/>\n          <div style="margin-top:10px;display:flex;gap:6px;flex-wrap:wrap">\n            <button class="btn bp admin-only" style="padding:9px 18px;font-size:12px" onclick="importBL()">⬆ Import budget lines</button>\n            <button class="btn bs" style="padding:9px 14px;font-size:12px" onclick="window.open(\'/api/export/template-budget-lines\',\'_blank\')">⬇ Template</button>\n          </div>\n          <div id="imp-bl-result" style="margin-top:8px"></div>\n        </div>\n      </div>\n    </div>\n    <div class="card">\n      <div class="ch"><h2>⬇ Exports</h2></div>\n      <div class="cb" style="display:flex;gap:8px;flex-wrap:wrap">\n        <button class="btn bs" onclick="window.open(`/api/export/transactions?year=${S.year}&direction=${S.dir}`,\'_blank\')">⬇ Transactions CSV</button>\n        <button class="btn bs" onclick="window.open(`/api/report/monthly?year=${S.year}&month=${new Date().getMonth()+1}`,\'_blank\')">⬇ Rapport mensuel</button>\n        <button class="btn bs" onclick="window.open(\'/api/export/template-transactions\',\'_blank\')">⬇ Template transactions</button>\n        <button class="btn bs" onclick="window.open(\'/api/export/template-budget-lines\',\'_blank\')">⬇ Template budget</button>\n      </div>\n    </div>\n  </div>\n\n  <!-- USERS -->\n  <div id="tab-users" class="tab-content">\n    <div class="card">\n      <div class="ch"><h2>👥 Gestion des utilisateurs</h2><button class="btn bp bsm" onclick="openUserModal()">+ Ajouter</button></div>\n      <div style="overflow-x:auto"><table class="u-tbl">\n        <thead><tr><th>Nom complet</th><th>Identifiant</th><th>Email</th><th>Rôle</th><th>Directions autorisées</th><th>Créé le</th><th></th></tr></thead>\n        <tbody id="usr-rows"></tbody>\n      </table></div>\n    </div>\n  </div>\n</div>\n\n<!-- BUDGET LINE MODAL -->\n<div class="mbg" id="bl-modal">\n  <div class="modal" style="max-width:580px">\n    <div class="mh"><h3>Nouvelle ligne budgétaire</h3><button class="btn bs bxs" onclick="closeModal(\'bl-modal\')">✕</button></div>\n    <div class="mb">\n      <div class="fr fc2">\n        <div class="fld"><label>Année *</label><input type="number" id="bl-yr" value="2025"/></div>\n        <div class="fld"><label>Direction *</label><select id="bl-dir"><option value="">—</option></select></div>\n      </div>\n      <div class="fld" style="margin-top:7px"><label>Imputation comptable *</label><input id="bl-imp" placeholder="SP4/DG/AD0025/VD0007/T00127/63840100"/></div>\n      <div class="fld" style="margin-top:7px"><label>Libellé</label><input id="bl-lib" placeholder="FRAIS DE MISSION A L\'EXTERIEUR"/></div>\n      <div class="fr fc2" style="margin-top:7px">\n        <div class="fld"><label>Nature</label><select id="bl-nat"><option>DEPENSE COURANTE</option><option>DEPENSE DE CAPITAL</option></select></div>\n        <div class="fld"><label>Budget CP (FCFA) *</label><input type="number" id="bl-bcp" placeholder="0"/></div>\n      </div>\n    </div>\n    <div class="mf"><button class="btn bs" onclick="closeModal(\'bl-modal\')">Annuler</button><button class="btn bp" onclick="saveBL()">💾 Enregistrer</button></div>\n  </div>\n</div>\n\n<!-- USER MODAL -->\n<div class="mbg" id="usr-modal">\n  <div class="modal" style="max-width:620px">\n    <div class="mh"><h3 id="usr-modal-title">Ajouter un utilisateur</h3><button class="btn bs bxs" onclick="closeModal(\'usr-modal\')">✕</button></div>\n    <div class="mb">\n      <div class="fr fc2">\n        <div class="fld"><label>Nom complet *</label><input id="u-nm" placeholder="Jean Dupont"/></div>\n        <div class="fld"><label>Identifiant *</label><input id="u-usr" placeholder="jdupont"/></div>\n      </div>\n      <div class="fr fc2" style="margin-top:7px">\n        <div class="fld"><label>Mot de passe</label><input type="password" id="u-pw" placeholder="Vide = ne pas changer"/></div>\n        <div class="fld"><label>Email</label><input id="u-em" placeholder="jean@camtel.cm"/></div>\n      </div>\n      <div class="fld" style="margin-top:7px"><label>Rôle *</label>\n        <select id="u-rl" onchange="onRoleChange()">\n          <option value="agent">Agent — saisie sur directions assignées</option>\n          <option value="agent_plus">Agent+ — saisie + import CSV</option>\n          <option value="viewer">Observateur — lecture seule</option>\n          <option value="dcf_sub">Sous-Directeur Budget — accès total</option>\n          <option value="dcf_dir">Directeur DCF — accès total</option>\n          <option value="admin">Administrateur — accès complet</option>\n        </select>\n      </div>\n      <div id="u-dirs-block" style="margin-top:11px">\n        <div style="font-size:10px;font-weight:700;color:var(--muted);margin-bottom:5px;text-transform:uppercase">DIRECTIONS AUTORISÉES</div>\n        <div style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:6px">\n          <button class="btn bs bsm" onclick="selAllDirs(true)">Tout sél.</button>\n          <button class="btn bs bsm" onclick="selAllDirs(false)">Tout désél.</button>\n        </div>\n        <div id="u-dirs-list" style="max-height:180px;overflow-y:auto;border:1px solid var(--bdr);border-radius:6px;padding:7px;display:grid;grid-template-columns:repeat(5,1fr);gap:2px"></div>\n      </div>\n    </div>\n    <div class="mf"><button class="btn bs" onclick="closeModal(\'usr-modal\')">Annuler</button><button class="btn bp" onclick="saveUser()">💾 Enregistrer</button></div>\n  </div>\n</div>\n\n<div id="toast" class="toast"></div>\n\n<script>\n\n\n// ── DESIGNATION & OM LOGIC ──────────────────────────────\nlet PLAN_COMPTABLE_DATA = [];\n\nasync function loadPlanComptable(designation="") {\n  const r = await api(`/api/plan-comptable?designation=${designation}`);\n  if (!r) return;\n  PLAN_COMPTABLE_DATA = await r.json();\n  populateCompteSelect();\n}\n\nfunction populateCompteSelect(filter="") {\n  const sel = document.getElementById("nr-compte-sel");\n  if (!sel) return;\n  const fl = filter.toLowerCase();\n  const opts = PLAN_COMPTABLE_DATA.filter(c =>\n    !fl || c.num.includes(fl) || c.nom.toLowerCase().includes(fl)\n  );\n  sel.innerHTML = \'<option value="">— Sélectionner compte —</option>\' +\n    opts.map(c => `<option value="${c.num}" data-name="${c.nom}">${c.num} — ${c.nom}</option>`).join("");\n}\n\nfunction filterComptes() {\n  const q = document.getElementById("nr-compte-search")?.value || "";\n  populateCompteSelect(q);\n}\n\nfunction selectCompte(sel) {\n  const opt = sel.options[sel.selectedIndex];\n  document.getElementById("nr-compte-num").value = sel.value;\n  document.getElementById("nr-compte-name").value = opt?.dataset?.name || "";\n\n  autoSetNatureFromCompte(sel.value,"nr-nature");\n}\n\nfunction onDesigChange() {\n  const desig = document.getElementById("nr-desig")?.value || "NC";\n  const omFields = document.getElementById("nr-om-fields");\n  const montantInput = document.getElementById("nr-montant");\n  if (omFields) {\n    if (desig === "OM") {\n      omFields.style.display = "block";\n      if (montantInput) { montantInput.readOnly = true; montantInput.style.background = "#f0f9ff"; }\n      // Clear non-OM\n      clearOMFields();\n    } else {\n      omFields.style.display = "none";\n      if (montantInput) { montantInput.readOnly = false; montantInput.style.background = ""; }\n    }\n  }\n  // Reload plan comptable suggestions for this designation\n  loadPlanComptable(desig);\n}\n\nfunction clearOMFields() {\n  ["nr-dep-date","nr-ret-date","nr-ndays","nr-apd"].forEach(id => {\n    const el = document.getElementById(id);\n    if (el) el.value = "";\n  });\n  const m = document.getElementById("nr-montant");\n  if (m) m.value = "";\n}\n\nfunction calcOMAmount() {\n  const dep = document.getElementById("nr-dep-date")?.value;\n  const ret = document.getElementById("nr-ret-date")?.value;\n  const apd = parseFloat(document.getElementById("nr-apd")?.value || 0);\n  if (dep && ret) {\n    const d1 = new Date(dep), d2 = new Date(ret);\n    if (d2 < d1) { toast("⚠ La date de retour doit être ≥ date de départ","#dc2626"); return; }\n    const ndays = Math.floor((d2 - d1) / 86400000) + 1;\n    const el = document.getElementById("nr-ndays");\n    if (el) el.value = ndays;\n    if (apd > 0) {\n      const total = ndays * apd;\n      const m = document.getElementById("nr-montant");\n      if (m) m.value = total;\n    }\n  }\n}\n\nfunction syncMontant() {\n  // For non-OM, montant is total_amount directly\n}\n\nfunction openFicheImputation(id) {\n  window.open(`/fiche-imputation?ids=${id}`, "_blank",\n    "width=900,height=700,scrollbars=yes,toolbar=no");\n}\n\n// ── PERIOD SEARCH ────────────────────────────────────────\nlet PERIOD_SEARCH_ACTIVE = false;\n\nasync function searchByPeriod() {\n  const month = document.getElementById("tx-s-month")?.value;\n  const year = document.getElementById("tx-s-year")?.value;\n  if (!year) { toast("⚠ Veuillez sélectionner une année","#f59e0b"); return; }\n  PERIOD_SEARCH_ACTIVE = true;\n  \n  const dir = document.getElementById("tx-f-dir")?.value || "";\n  const r = await api(`/api/transactions/search?year=${year}&month=${month||0}&direction=${encodeURIComponent(dir)}`);\n  if (!r) return;\n  const data = await r.json();\n  \n  const MOIS = ["","Janvier","Février","Mars","Avril","Mai","Juin","Juillet","Août","Septembre","Octobre","Novembre","Décembre"];\n  const info = month ? `${MOIS[parseInt(month)]} ${year}` : `Année ${year}`;\n  const infoEl = document.getElementById("tx-search-info");\n  if (infoEl) infoEl.textContent = `→ ${data.length} transaction(s) — ${info}`;\n  \n  renderTxTable(data);\n}\n\nfunction clearPeriodSearch() {\n  PERIOD_SEARCH_ACTIVE = false;\n  document.getElementById("tx-s-month").value = "";\n  document.getElementById("tx-s-year").value = "";\n  const infoEl = document.getElementById("tx-search-info");\n  if (infoEl) infoEl.textContent = "";\n  loadTx();\n}\n\nfunction populateSearchYears() {\n  const sel = document.getElementById("tx-s-year");\n  if (!sel || !S.user?.available_years) return;\n  sel.innerHTML = \'<option value="">— Année —</option>\' +\n    S.user.available_years.map(y => `<option value="${y}">${y}</option>`).join("");\n}\n\n// ── LANGUAGE SYSTEM ──────────────────────────────────────────\nlet LANG = localStorage.getItem(\'camtel_lang\') || \'fr\';\nconst T = {\n  fr: {\n    dashboard:"📊 Dashboard", transactions:"📋 Transactions", budgetlines:"📂 Lignes Budget",\n    reports:"📈 Rapports", importexport:"⬆ Import/Export", users:"👥 Utilisateurs",\n    logout:"Déconnexion", alldirs:"Toutes directions", allyears:"Toutes années",\n    allstatus:"Tous statuts", allstatbud:"Tous statuts budget", newline:"➕ Nouvelle ligne",\n    printsel:"🖨 Imprimer sélection", noTx:"Aucune transaction. Cliquez ➕ Nouvelle ligne pour ajouter.",\n    year:"ANNÉE", direction:"DIRECTION", refresh:"↻ Actualiser",\n    validated:"Validé", pending:"Brouillon", normal:"Normal (OK)", depassement:"Dépassement",\n    totalbudget:"Budget CP Total", totalengage:"Cumul Engagé", onhold:"En Attente", available:"Disponible Après"\n  },\n  en: {\n    dashboard:"📊 Dashboard", transactions:"📋 Transactions", budgetlines:"📂 Budget Lines",\n    reports:"📈 Reports", importexport:"⬆ Import/Export", users:"👥 Users",\n    logout:"Logout", alldirs:"All directions", allyears:"All years",\n    allstatus:"All statuses", allstatbud:"All budget statuses", newline:"➕ New line",\n    printsel:"🖨 Print selection", noTx:"No transactions. Click ➕ New line to add.",\n    year:"YEAR", direction:"DIRECTION", refresh:"↻ Refresh",\n    validated:"Validated", pending:"Draft", normal:"Normal (OK)", depassement:"Overspend",\n    totalbudget:"Total CP Budget", totalengage:"Total Committed", onhold:"On Hold", available:"Available After"\n  }\n};\nfunction t(key){ return (T[LANG]||T.fr)[key] || key; }\nfunction toggleLang(){\n  LANG = LANG===\'fr\'?\'en\':\'fr\';\n  localStorage.setItem(\'camtel_lang\', LANG);\n  document.getElementById(\'lang-btn\').textContent = \'🌐 \' + (LANG===\'fr\'?\'EN\':\'FR\');\n  applyLang();\n}\nfunction applyLang(){\n  // Nav labels\n  document.getElementById(\'nav-dashboard\').textContent = t(\'dashboard\');\n  document.getElementById(\'nav-transactions\').textContent = t(\'transactions\');\n  document.getElementById(\'nav-budgetlines\').textContent = t(\'budgetlines\');\n  document.getElementById(\'nav-reports\').textContent = t(\'reports\');\n  const nim = document.getElementById(\'nav-import\');\n  if(nim) nim.textContent = t(\'importexport\');\n  // KPI labels\n  const kl = document.querySelectorAll(\'.kpi label\');\n  if(kl[0]) kl[0].textContent = t(\'totalbudget\');\n  if(kl[1]) kl[1].textContent = t(\'totalengage\');\n  if(kl[2]) kl[2].textContent = t(\'onhold\');\n  if(kl[3]) kl[3].textContent = t(\'available\');\n  // Refresh\n  const rb=document.querySelector(\'.gbar .btn.bs.bsm\');\n  if(rb) rb.textContent=t(\'refresh\');\n  // Tx empty\n  const te=document.getElementById(\'tx-empty\');\n  if(te) te.innerHTML=t(\'noTx\');\n  // Selects\n  const gd=document.getElementById(\'g-dir\'); if(gd&&gd.options[0]) gd.options[0].textContent=t(\'alldirs\');\n  const td=document.getElementById(\'tx-f-dir\'); if(td&&td.options[0]) td.options[0].textContent=t(\'alldirs\');\n  const tfy=document.getElementById(\'tx-f-year\'); if(tfy&&tfy.options[0]) tfy.options[0].textContent=t(\'allyears\');\n}\n\nconst ALL_DIRS=["BUM","BUT","BUF","DG","DRH","DICOM","DIRCAB","DCRA","DAMR","DC","DNQ","DAS","DFA","DAJR","DAP","DR","DS","DSPI","DSIR","DOP","DT","DCF","DCRM","DRLM","RRSM","RREM","RROM","RRNOM","RRSOM","RRAM","RRNM","RRENM","DCRF","DRLF","RRSF","RREF","RROF","RRNOF","RRSOF","RRAF","RRNF","RRENF","DCRT","DRLT","RRNOT","RRENT"];\nconst NATURES=["DEPENSE COURANTE","DEPENSE DE CAPITAL","PRESTATION DE SERVICES","SERVICES ET FRAIS DIVERS","TRAVAUX","FOURNITURES","IMMOBILISATION"];\n\nlet S={user:null,year:new Date().getFullYear(),dir:"",cDir:null,cMo:null,editUserId:null,selectedTxIds:new Set()};\nlet BL_CACHE={};\n\n// Format with space thousands: 27 311 774 252 FCFA\nconst fmtFCFA=n=>{\n  n=Math.round(Number(n||0));\n  if(isNaN(n))return "0 FCFA";\n  const s=Math.abs(n).toString().replace(/\\B(?=(\\d{3})+(?!\\d))/g,"\\u00a0");\n  return (n<0?"-":"")+s+"\\u00a0FCFA";\n};\nconst fmts=n=>{n=Number(n||0);if(n>=1e9)return (n/1e9).toFixed(1)+" Md";if(n>=1e6)return (n/1e6).toFixed(1)+" M";if(n>=1e3)return Math.round(n/1e3)+" K";return Math.round(n).toLocaleString("fr-FR");};\nconst fmtDisp=n=>`<span style="color:${n>=0?"#16a34a":"#dc2626"};font-weight:800">${fmtFCFA(n)}</span>`;\n\nlet _dt={};\nconst debounce=(f,ms)=>{clearTimeout(_dt[f]);_dt[f]=setTimeout(f,ms);};\nconst toast=(msg,ok=true)=>{const t=document.getElementById("toast");t.textContent=msg;t.style.background=ok?"#16a34a":"#dc2626";t.style.display="block";setTimeout(()=>t.style.display="none",3500);};\nconst api=async(path,opts)=>{const r=await fetch(path,{credentials:"include",...(opts||{})});if(r.status===401){window.location="/login";return null;}return r;};\nconst openModal=id=>document.getElementById(id).classList.add("open");\nconst closeModal=id=>document.getElementById(id).classList.remove("open");\nconst isFullAccess=()=>S.user&&["admin","dcf_dir","dcf_sub"].includes(S.user.role);\nconst canImport=()=>S.user&&["admin","dcf_dir","dcf_sub","agent_plus"].includes(S.user.role);\nconst myDirs=()=>isFullAccess()?ALL_DIRS:(()=>{try{return JSON.parse(S.user.dirs||"[]")}catch{return []}})();\n\nfunction initYears(){\n  const n=new Date().getFullYear();\n  ["g-year","rp-year"].forEach(id=>{\n    const s=document.getElementById(id);if(!s)return;\n    for(let y=n-3;y<=n+2;y++){const o=document.createElement("option");o.value=y;o.textContent=y;s.appendChild(o);}\n    s.value=n;\n  });\n  S.year=n;\n}\nasync function refreshUserMeta(){\n  const r=await api("/api/me");if(!r)return;\n  S.user=await r.json();\n  const years=S.user.available_years||[];\n  ["g-year","rp-year","tx-f-year"].forEach(id=>{\n    const sel=document.getElementById(id);if(!sel)return;\n    const cur=sel.value;\n    while(sel.options.length>1)sel.remove(1);\n    years.forEach(y=>{const o=document.createElement("option");o.value=y;o.textContent=y;sel.appendChild(o);});\n    if(cur&&years.includes(Number(cur)))sel.value=cur;\n    else if(id==="tx-f-year")sel.value="";\n    else if(id==="g-year"&&S.user.default_year){sel.value=S.user.default_year;S.year=S.user.default_year;}\n  });\n  populateSearchYears();\n}\nfunction populateDirSelects(dirs){\n  ["g-dir","tx-f-dir","bl-f-dir"].forEach(id=>{\n    const s=document.getElementById(id);if(!s)return;\n    const cur=s.value;\n    s.innerHTML="<option value=\\"\\">Toutes directions</option>";\n    dirs.forEach(d=>{const o=document.createElement("option");o.value=d;o.textContent=d;s.appendChild(o);});\n    if(cur&&dirs.includes(cur))s.value=cur;\n  });\n  const blDir=document.getElementById("bl-dir");\n  if(blDir){blDir.innerHTML="<option value=\\"\\">—</option>";ALL_DIRS.forEach(d=>{const o=document.createElement("option");o.value=d;o.textContent=d;blDir.appendChild(o);});}\n}\nfunction onYearChange(){S.year=Number(document.getElementById("g-year").value);BL_CACHE={};refreshAll();}\nfunction onDirChange(){S.dir=document.getElementById("g-dir").value;refreshAll();}\nfunction showTab(n){\n  document.querySelectorAll(".tab-content").forEach(e=>e.classList.remove("active"));\n  document.querySelectorAll("nav button").forEach(b=>b.classList.remove("active"));\n  document.getElementById("tab-"+n).classList.add("active");\n  document.getElementById("nav-"+n)?.classList.add("active");\n  if(n==="transactions"){const tfY=document.getElementById("tx-f-year");if(tfY&&!tfY._userPicked)tfY.value="";}\n  if(n==="reports"){const rpY=document.getElementById("rp-year");if(rpY&&!rpY.value)rpY.value=S.year;loadReports();return;}\n  ({dashboard:loadDash,transactions:loadTx,budgetlines:loadBL,reports:loadReports,users:loadUsers,planning:()=>{}})[n]?.();\n}\nfunction refreshAll(){\n  loadKPIs();\n  const a=document.querySelector(".tab-content.active")?.id?.replace("tab-","");\n  ({dashboard:loadDash,transactions:loadTx,budgetlines:loadBL,reports:loadReports})[a]?.();\n  document.getElementById("last-upd").textContent="Actualisé: "+new Date().toLocaleTimeString("fr-FR");\n}\n\nasync function loadKPIs(){\n  const r=await api(`/api/dashboard?year=${S.year}`);if(!r)return;\n  const d=await r.json();\n  document.getElementById("kpi-bud").textContent=fmts(d.total_budget);\n  document.getElementById("kpi-eng").textContent=fmts(d.total_engage);\n  document.getElementById("kpi-eng-s").textContent=d.tx_count+" transaction(s) validée(s)";\n  document.getElementById("kpi-pend").textContent=fmts(d.total_pending);\n  document.getElementById("kpi-pend-s").textContent=d.pending_count+" brouillon(s)";\n  document.getElementById("kpi-dispo").textContent=fmts(d.total_dispo);\n  const pct=d.total_budget?Math.round(d.total_engage/d.total_budget*100):0;\n  document.getElementById("kpi-dispo-s").textContent=pct+"% du budget engagé";\n  // Mirror KPIs in import tab\n  const upd2=(id,v)=>{const el=document.getElementById(id);if(el)el.textContent=v;};\n  upd2("kpi-bud-imp",fmts(d.total_budget));upd2("kpi-bud-s-imp","");upd2("kpi-eng2",fmts(d.total_engage));upd2("kpi-eng-s2",d.tx_count+" transaction(s) validée(s)");\n  upd2("kpi-pend2",fmts(d.total_pending));upd2("kpi-pend-s2",d.pending_count+" brouillon(s)");\n  upd2("kpi-dispo2",fmts(d.total_dispo));upd2("kpi-dispo-s2",pct+"% du budget engagé");\n  const ar=document.getElementById("alerts-row");ar.innerHTML="";\n  (d.overdrawn||[]).forEach(a=>{ar.innerHTML+=`<div class="alrt alrt-r">🚨 <strong>${a.direction}</strong> — dépassement de <strong>${fmtFCFA(a.montant)}</strong></div>`;});\n}\n\nconst TICKER_MSGS=["🌐 CAMTEL — Cameroon Telecommunications. Bienvenue dans le système de gestion budgétaire.","📡 Suivi en temps réel des engagements budgétaires par direction.","💼 Toutes les transactions sont enregistrées et traçables dans le système.","🔒 Accès sécurisé — vos données sont protégées et confidentielles.","📊 Utilisez Rapports pour générer vos rapports mensuels ou annuels complets.","⚡ Importez vos fichiers CSV pour une mise à jour instantanée du tableau de bord.","🎯 Contrôle budgétaire rigoureux pour une gestion financière optimale."];\nlet _tickIdx=0,_tickTimer=null;\nfunction startTicker(){\n  const el=document.getElementById("dash-ticker");if(!el)return;\n  function showNext(){el.style.opacity="0";setTimeout(()=>{el.textContent=TICKER_MSGS[_tickIdx%TICKER_MSGS.length];_tickIdx++;el.style.opacity="1";},400);}\n  showNext();if(_tickTimer)clearInterval(_tickTimer);_tickTimer=setInterval(showNext,5000);\n}\nfunction startClock(){\n  function tick(){const cl=document.getElementById("hero-clock");if(!cl)return;const n=new Date();cl.textContent=n.toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit",second:"2-digit"})+" — "+n.toLocaleDateString("fr-FR",{weekday:"short",day:"2-digit",month:"short",year:"numeric"});}\n  tick();setInterval(tick,1000);\n}\nasync function loadDash(){\n  startTicker();startClock();\n  await loadKPIs();\n  const r=await api(`/api/dashboard?year=${S.year}`);if(!r)return;\n  const d=await r.json();\n  const dirs=Object.keys(d.by_dir).sort((a,b)=>d.by_dir[b]-d.by_dir[a]).slice(0,12);\n  const cols=["#00d4ff","#00e676","#ffb300","#ff4444","#b47fff","#00bcd4","#f06292","#aeea00","#ff7043","#26c6da","#ce93d8","#29b6f6"];\n  if(S.cDir)S.cDir.destroy();\n  S.cDir=new Chart(document.getElementById("ch-dir"),{type:"bar",data:{labels:dirs,datasets:[{data:dirs.map(x=>d.by_dir[x]),backgroundColor:cols.map(c=>c+"aa"),borderColor:cols,borderWidth:1,borderRadius:6,borderSkipped:false}]},options:{responsive:true,plugins:{legend:{display:false}},scales:{x:{ticks:{color:"#7aaccc",font:{size:9}},grid:{color:"rgba(0,80,160,.15)"}},y:{ticks:{color:"#7aaccc",font:{size:9},callback:v=>fmts(v)},grid:{color:"rgba(0,80,160,.15)"}}}}});\n  const months=["Jan","Fév","Mar","Avr","Mai","Jun","Jul","Aoû","Sep","Oct","Nov","Déc"];\n  if(S.cMo)S.cMo.destroy();\n  S.cMo=new Chart(document.getElementById("ch-mo"),{type:"line",data:{labels:months,datasets:[{data:d.by_month,borderColor:"#00d4ff",backgroundColor:"rgba(0,180,255,.08)",fill:true,tension:.4,pointRadius:5,pointBackgroundColor:"#00d4ff",pointBorderColor:"#0a1628",pointBorderWidth:2}]},options:{responsive:true,plugins:{legend:{display:false}},scales:{x:{ticks:{color:"#7aaccc",font:{size:9}},grid:{color:"rgba(0,80,160,.15)"}},y:{ticks:{color:"#7aaccc",font:{size:9},callback:v=>fmts(v)},grid:{color:"rgba(0,80,160,.15)"}}}}});\n  const dp=document.getElementById("dir-prog");const bld=d.bl_by_dir||{};const dk=Object.keys(bld).sort();\n  dp.innerHTML=dk.length?`<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));gap:9px">${dk.map(dir=>{const bd=bld[dir];const pct=bd.budget_cp?Math.min(100,Math.round(bd.engage/bd.budget_cp*100)):0;const col=pct>90?"#ff4444":pct>70?"#ffb300":"#00e676";const av=bd.budget_cp-bd.engage;return `<div style="padding:10px 12px;background:linear-gradient(135deg,rgba(8,20,50,.95),rgba(4,12,40,.98));border:1px solid rgba(0,160,240,.15);border-left:3px solid ${col};border-radius:8px;box-shadow:0 2px 12px rgba(0,0,0,.4);transition:transform .15s;" onmouseover="this.style.transform=\'translateY(-2px)\'" onmouseout="this.style.transform=\'\'"><div style="display:flex;justify-content:space-between;font-size:12px;font-weight:800;margin-bottom:4px"><span style="color:#c8daf0">${dir}</span><span style="color:${col};font-size:13px">${pct}%</span></div><div style="font-size:10px;color:#5a8aaa;margin:2px 0">CP: ${fmtFCFA(bd.budget_cp)}</div><div style="font-size:11px;font-weight:700;color:${av>=0?"#00e676":"#ff4444"};margin:3px 0 4px">${av>=0?"✓ Dispo":"⚠ Dépass"}: ${fmtFCFA(Math.abs(av))}</div><div style="height:4px;background:rgba(0,40,100,.4);border-radius:2px;overflow:hidden"><div style="height:100%;width:${pct}%;background:linear-gradient(90deg,${col}88,${col});box-shadow:0 0 6px ${col};border-radius:2px;"></div></div></div>`;}).join("")}</div>`:"<div style=\'padding:16px;text-align:center;color:#5a8aaa\'>Aucune ligne budgétaire. Importez d\\\'abord via ⬆ Import/Export.</div>";\n  const rr=document.getElementById("rec-rows");rr.innerHTML="";\n  (d.recent||[]).forEach(t=>rr.innerHTML+=buildRow(t));\n}\n\nfunction natBadge(n){n=n||"";if(n.includes("CAPITAL"))return`<span class="nat-k">CAPITAL</span>`;if(n.includes("SERVICES"))return`<span class="nat-s">SERVICES</span>`;return`<span class="nat-c">COURANTE</span>`;}\n\nfunction buildRow(t){\n  const dep=t.statut_budget==="DEPASSEMENT";\n  const pend=t.status==="pending";\n  const rc=dep?"row-dep":pend?"row-pend":"row-ok";\n  const sel=S.selectedTxIds.has(t.id)?"checked":"";\n  const sb=dep?`<span class="sb-dep">⚠ DÉPASSEMENT</span>`:`<span class="sb-ok">✓ OK</span>`;\n  const stlbl=t.status==="validated"?`<span style="font-size:10px;color:#16a34a;font-weight:700">✓</span>`:`<span style="font-size:10px;color:#d97706;font-weight:700">◷</span>`;\n  return `<tr class="${rc}" id="tx-tr-${t.id}">\n    <td class="tc"><input type="checkbox" class="tx-chk" value="${t.id}" ${sel} onchange="onTxSel(this)"/></td>\n    <td class="td-date">${t.date_reception||"—"}</td>\n    <td class="td-code" title="${t.code_ref}">${t.code_ref||"—"}</td>\n    <td class="tc"><span class="dir-b">${t.direction}</span></td>\n    <td class="td-imp" title="${t.imputation}">${t.imputation||"—"}</td>\n    <td>${natBadge(t.nature)}</td>\n    <td class="td-int" title="${t.intitule}">${t.intitule||"—"}</td>\n    <td class="td-amt">${fmtFCFA(t.montant)}</td>\n    <td class="td-bcp">${t.budget_cp_val?fmtFCFA(t.budget_cp_val):"—"}</td>\n    <td class="td-cum">${t.cumul_engage?fmtFCFA(t.cumul_engage):"—"}</td>\n    <td class="td-dis">${fmtDisp(t.disponible_val!==undefined?t.disponible_val:(t.budget_cp_val?t.budget_cp_val-t.cumul_engage:0))}</td>\n    <td class="tc">${sb}</td>\n    <td style="white-space:nowrap">${stlbl} <button class="btn bs bxs" onclick="openFiche(${t.id})">🖨</button>${isFullAccess()?` <button class="btn bd bxs" onclick="delTx(${t.id})">🗑</button>`:""}</td>\n  </tr>`;\n}\n\nasync function loadTx(){\n  const dir=document.getElementById("tx-f-dir").value;\n  const st=document.getElementById("tx-f-status").value;\n  const sb=document.getElementById("tx-f-statbud").value;\n  const q=document.getElementById("tx-q").value;\n  const fy=document.getElementById("tx-f-year")?.value||"";\n  // Use cross-year search if query or "all years" selected\n  const yr=fy?Number(fy):0;\n  const r=await api(`/api/transactions/search?year=${yr}&direction=${encodeURIComponent(dir)}&status=${st}&q=${encodeURIComponent(q)}`);if(!r)return;\n  let data=await r.json();\n  if(sb)data=data.filter(t=>t.statut_budget===sb);\n  if(st)data=data.filter(t=>t.status===st);\n  const bnr=document.getElementById("tx-all-years-banner");\n  if(bnr){if(!fy){const yrs=[...new Set(data.map(t=>t.year))].sort((a,b)=>b-a);bnr.style.display=data.length?"block":"none";bnr.textContent=`📋 ${data.length} transaction(s) — toutes années: ${yrs.join(", ")||"—"}`;}else bnr.style.display="none";}\n  const tb=document.getElementById("tx-rows");tb.innerHTML="";\n  document.getElementById("tx-empty").style.display=data.length?"none":"block";\n  document.getElementById("tx-foot").style.display=data.length?"flex":"none";\n  let tot=0;data.forEach(t=>{tot+=t.montant;tb.innerHTML+=buildRow(t);});\n  document.getElementById("tx-foot-count").textContent=data.length+" transaction(s)";\n  document.getElementById("tx-foot-total").textContent="Total: "+fmtFCFA(tot);\n  updateSelUI();\n}\n\nasync function addNewRow(){\n  document.getElementById("new-tx-row")?.remove();\n  document.getElementById("tx-empty").style.display="none";\n  const dirs=myDirs();\n  const dirOpts=dirs.map(d=>`<option value="${d}">${d}</option>`).join("");\n  const natOpts=NATURES.map(n=>`<option>${n}</option>`).join("");\n  const today=new Date().toISOString().slice(0,10);\n  const row=document.createElement("tr");\n  row.id="new-tx-row";row.className="new-row";\n  row.innerHTML=`\n    <td><button class="btn bd bxs" onclick="cancelNewRow()">✕</button></td>\n    <td><input type="date" id="nr-date" value="${today}" style="min-width:130px"/></td>\n    <td style="font-size:9px;color:#666">Auto</td>\n    <td><select id="nr-dir" onchange="onNrDirChange(this)" style="min-width:85px"><option value="">—</option>${dirOpts}</select></td>\n    <td><select id="nr-imp" onchange="onNrImpChange(this)" style="min-width:220px"><option value="">— Choisir direction —</option></select></td>\n    <td><select id="nr-nat" style="min-width:110px">${natOpts}</select></td>\n    <td><input id="nr-int" placeholder="Intitulé de la commande..." style="min-width:160px"/></td>\n    <td class="td-amt"><input type="number" id="nr-amt" placeholder="0" style="min-width:100px;text-align:right" oninput="onNrAmtChange()"/></td>\n    <td id="nr-bcp" class="td-bcp">—</td>\n    <td id="nr-cum" class="td-cum">—</td>\n    <td id="nr-dis">—</td>\n    <td><select id="nr-stat"><option value="validated">✓ Validé</option><option value="pending">◷ Brouillon</option></select></td>\n    <td><button class="btn bp bxs" onclick="saveNewRow()" style="white-space:nowrap">💾 Enregistrer</button></td>`;\n  const tb=document.getElementById("tx-rows");tb.insertBefore(row,tb.firstChild);\n  if(S.dir&&dirs.includes(S.dir)){document.getElementById("nr-dir").value=S.dir;await onNrDirChange(document.getElementById("nr-dir"));}\n  document.getElementById("nr-date").focus();\n}\n\nasync function onNrDirChange(sel){\n  const dir=sel.value;const imp=document.getElementById("nr-imp");\n  imp.innerHTML="<option value=\\"\\">— Chargement... —</option>";\n  if(!dir){imp.innerHTML="<option value=\\"\\">— Choisir direction —</option>";return;}\n  const r=await api(`/api/budget-lines?year=${S.year}&direction=${dir}`);if(!r)return;\n  const bls=await r.json();\n  bls.forEach(b=>{BL_CACHE[`${b.direction}|${b.imputation}|${b.year}`]=b;});\n  imp.innerHTML="<option value=\\"\\">— Sélectionner ligne budgétaire —</option>";\n  if(!bls.length){imp.innerHTML="<option value=\\"\\">Aucune ligne pour cette direction</option>";return;}\n  bls.forEach(b=>{\n    const o=document.createElement("option");o.value=b.imputation;\n    const ok=b.disponible>=0;\n    o.textContent=`${b.imputation.split("/").slice(-1)[0]} | ${b.libelle||""} | ${ok?"✅":"⚠"} ${fmtFCFA(b.disponible)}`;\n    o.dataset.bcp=b.budget_cp;o.dataset.cum=b.cumul_engage;o.dataset.dis=b.disponible;\n    imp.appendChild(o);\n  });\n  if(bls.length===1){imp.value=bls[0].imputation;onNrImpChange(imp);}\n}\n\nfunction onNrImpChange(sel){\n  const opt=sel.options[sel.selectedIndex];\n  if(!opt||!opt.value){document.getElementById("nr-bcp").textContent="—";document.getElementById("nr-dis").innerHTML="—";return;}\n  document.getElementById("nr-bcp").textContent=fmtFCFA(Number(opt.dataset.bcp||0));\n  document.getElementById("nr-cum").textContent=fmtFCFA(Number(opt.dataset.cum||0));\n  onNrAmtChange();\n}\nfunction onNrAmtChange(){\n  const imp=document.getElementById("nr-imp");const opt=imp.options[imp.selectedIndex];\n  if(!opt||!opt.value){return;}\n  const d=Number(opt.dataset.dis||0)-Number(document.getElementById("nr-amt").value||0);\n  document.getElementById("nr-dis").innerHTML=fmtDisp(d+(Number(opt.dataset.dis||0)-(Number(opt.dataset.dis||0)-Number(opt.dataset.cum||0)+Number(opt.dataset.cum||0))));\n  // Simpler: new disponible = original_dispo - new_amount_entered\n  const origDis=Number(opt.dataset.dis||0);\n  const amt=Number(document.getElementById("nr-amt").value||0);\n  document.getElementById("nr-dis").innerHTML=fmtDisp(origDis-amt);\n}\n\nasync function saveNewRow(){\n  const dir=document.getElementById("nr-dir").value;\n  const imp=document.getElementById("nr-imp").value;\n  const date_=document.getElementById("nr-date").value;\n  const amt=Number(document.getElementById("nr-amt").value||0);\n  const intitule=document.getElementById("nr-int").value.trim();\n  const nat=document.getElementById("nr-nat").value;\n  const stat=document.getElementById("nr-stat").value;\n  if(!dir||!imp||!date_||!amt||!intitule){toast("Champs obligatoires: direction, imputation, date, montant, intitulé",false);return;}\n  const p={direction:dir,imputation:imp,date_reception:date_,montant:amt,intitule:intitule,nature:nat,status:stat,year:S.year};\n  const r=await api("/api/transactions",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p)});\n  if(!r)return;\n  if(!r.ok){toast("Erreur: "+(await r.text()),false);return;}\n  BL_CACHE={};const tx=await r.json();toast("Transaction enregistrée ✓");\n  document.getElementById("new-tx-row").remove();\n  await loadTx();loadKPIs();\n  // Show print options modal\n    const printChoice = confirm("🖨 Imprimer la Fiche de Suivi Budgétaire?");\n    if(printChoice) openFiche(tx.id);\n    setTimeout(()=>{\n      const printImp = confirm("📋 Imprimer aussi la Fiche d\'Imputation? (Optionnel)");\n      if(printImp) openFicheImputation(tx.id);\n    }, 300);\n}\nfunction cancelNewRow(){document.getElementById("new-tx-row")?.remove();}\n\nfunction onTxSel(cb){\n  const id=Number(cb.value);\n  if(cb.checked)S.selectedTxIds.add(id);else S.selectedTxIds.delete(id);\n  document.getElementById("tx-tr-"+id)?.classList.toggle("row-sel",cb.checked);\n  updateSelUI();\n}\nfunction toggleSelAll(cb){document.querySelectorAll(".tx-chk").forEach(c=>{c.checked=cb.checked;onTxSel(c);});}\nfunction updateSelUI(){\n  const n=S.selectedTxIds.size;\n  document.getElementById("print-sel-btn").style.display=n>0?"":"none";\n  document.getElementById("tx-sel-info").style.display=n>0?"flex":"none";\n  document.getElementById("tx-sel-count").textContent=n;\n}\nfunction printSelected(){if(!S.selectedTxIds.size){toast("Sélectionnez au moins une transaction",false);return;}window.open("/fiche?ids="+[...S.selectedTxIds].join(","),"_blank");}\nfunction openFiche(id){window.open("/fiche?ids="+id,"_blank");}\nasync function delTx(id){if(!confirm("Supprimer?"))return;await api("/api/transactions/"+id,{method:"DELETE"});BL_CACHE={};toast("Supprimé");loadTx();loadKPIs();}\nfunction exportTx(){window.open(`/api/export/transactions?year=${S.year}&direction=${S.dir}`,"_blank");}\n\nasync function loadBL(){\n  const dir=document.getElementById("bl-f-dir").value;\n  const q=(document.getElementById("bl-q").value||"").toLowerCase();\n  const r=await api(`/api/budget-lines?year=${S.year}&direction=${encodeURIComponent(dir)}`);if(!r)return;\n  let data=await r.json();\n  if(q)data=data.filter(b=>b.imputation.toLowerCase().includes(q)||(b.libelle||"").toLowerCase().includes(q));\n  const tb=document.getElementById("bl-rows");tb.innerHTML="";\n  document.getElementById("bl-empty").style.display=data.length?"none":"block";\n  data.forEach(b=>{\n    const pct=b.budget_cp?Math.min(100,Math.round(b.cumul_engage/b.budget_cp*100)):0;\n    const col=pct>90?"#dc2626":pct>70?"#d97706":"#16a34a";\n    const rc=pct>=100?"bl-dep":b.dispo_ok?"bl-ok":"";\n    const sl=pct>=100?`<span class="sb-dep">⚠ DÉPASSEMENT</span>`:b.dispo_ok?`<span class="sb-ok">✓ DISPONIBLE</span>`:`<span class="sb-pen">⚡ PARTIEL</span>`;\n    tb.innerHTML+=`<tr class="${rc}">\n      <td><span class="dir-b">${b.direction}</span></td>\n      <td style="font-family:monospace;font-size:10px;max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${b.imputation}">${b.imputation}</td>\n      <td style="max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${b.libelle||"—"}</td>\n      <td>${natBadge(b.nature)}</td>\n      <td class="num" style="color:#065f46">${fmtFCFA(b.budget_cp)}</td>\n      <td class="num" style="color:#7c3aed">${fmtFCFA(b.cumul_engage)}</td>\n      <td class="num">${fmtDisp(b.disponible)}</td>\n      <td style="min-width:90px"><div style="display:flex;align-items:center;gap:4px"><div class="prg" style="flex:1"><div class="prf" style="width:${pct}%;background:${col}"></div></div><span style="font-size:10px;color:${col};font-weight:800">${pct}%</span></div></td>\n      <td>${sl}</td>\n      <td class="admin-only"><button class="btn bd bxs" onclick="delBL(${b.id})">🗑</button></td>\n    </tr>`;\n  });\n}\nfunction openBLModal(){document.getElementById("bl-yr").value=S.year;if(S.dir)document.getElementById("bl-dir").value=S.dir;openModal("bl-modal");}\nasync function saveBL(){\n  const p={year:Number(document.getElementById("bl-yr").value),direction:document.getElementById("bl-dir").value,imputation:document.getElementById("bl-imp").value.trim(),libelle:document.getElementById("bl-lib").value.trim(),nature:document.getElementById("bl-nat").value,budget_cp:Number(document.getElementById("bl-bcp").value||0)};\n  if(!p.year||!p.direction||!p.imputation||!p.budget_cp){toast("Champs obligatoires manquants",false);return;}\n  const r=await api("/api/budget-lines",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p)});\n  if(!r)return;if(!r.ok){toast("Erreur: "+(await r.text()),false);return;}\n  BL_CACHE={};toast("Ligne créée ✓");closeModal("bl-modal");loadBL();loadKPIs();\n}\nasync function delBL(id){if(!confirm("Supprimer?"))return;await api("/api/budget-lines/"+id,{method:"DELETE"});BL_CACHE={};toast("Supprimé");loadBL();}\n\nasync function loadReports(){\n  const yr=Number(document.getElementById("rp-year").value||S.year);\n  const mo=Number(document.getElementById("rp-month").value);\n  const isFullYear=(mo===0);\n  const MOIS_EN=["January","February","March","April","May","June","July","August","September","October","November","December"];\n  const MOIS_FR=["Janvier","Février","Mars","Avril","Mai","Juin","Juillet","Août","Septembre","Octobre","Novembre","Décembre"];\n  document.getElementById("rp-year-label").textContent=isFullYear?`${yr} (Full Year)`:MOIS_EN[mo-1]+" "+yr;\n  const bdEl=document.getElementById("rp-breakdown-year");if(bdEl)bdEl.textContent=yr;\n  const r=await api(`/api/dashboard?year=${yr}`);if(!r)return;\n  const d=await r.json();\n  const pct=d.total_budget?Math.round(d.total_engage/d.total_budget*100):0;\n  // KPI strip\n  document.getElementById("rp-kpi-budget").textContent=fmtFCFA(d.total_budget);\n  document.getElementById("rp-kpi-engage").textContent=fmtFCFA(d.total_engage);\n  document.getElementById("rp-kpi-txcount").textContent=(d.tx_count||0)+" transaction(s) validated";\n  document.getElementById("rp-kpi-pending").textContent=fmtFCFA(d.total_pending);\n  document.getElementById("rp-kpi-draftcount").textContent=(d.pending_count||0)+" draft(s)";\n  const dispoEl=document.getElementById("rp-kpi-dispo");dispoEl.textContent=fmtFCFA(d.total_dispo);\n  dispoEl.style.color=d.total_dispo>=0?"#00e676":"#ff4444";\n  document.getElementById("rp-kpi-pct").textContent=pct+"% of the budget committed";\n  // Annual summary card\n  document.getElementById("rp-summary").innerHTML=`<div style="font-size:12px;padding:4px 0">\n    <div style="display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px solid rgba(0,60,120,.3)"><span style="color:#b8d0ec">Total CP Budget</span><strong style="font-size:13px;color:#e2eaff">${fmtFCFA(d.total_budget)}</strong></div>\n    <div style="display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px solid rgba(0,60,120,.3)"><span style="color:#ff6b6b;font-weight:600">Cumulative commitment</span><strong style="color:#ff6b6b;font-size:13px">${fmtFCFA(d.total_engage)}</strong></div>\n    <div style="display:flex;justify-content:space-between;padding:7px 0;border-bottom:1px solid rgba(0,60,120,.3)"><span style="color:#ffb300;font-weight:600">On hold</span><strong style="color:#ffb300;font-size:13px">${fmtFCFA(d.total_pending)}</strong></div>\n    <div style="display:flex;justify-content:space-between;padding:10px 0;border-top:1px solid rgba(0,100,200,.3);margin-top:4px"><strong style="font-size:14px;color:#e2eaff">Available</strong><strong style="font-size:14px;color:${d.total_dispo>=0?"#00e676":"#ff4444"}">${fmtFCFA(d.total_dispo)}</strong></div>\n    <div style="font-size:10px;color:#5a8aaa;margin-top:2px">${pct}% committed · ${d.tx_count||0} transaction(s)</div>\n  </div>`;\n  // Monthly breakdown\n  const breakDiv=document.getElementById("rp-monthly-breakdown");\n  if(isFullYear){\n    breakDiv.style.display="block";\n    const r2=await api(`/api/transactions/search?year=${yr}&direction=`);\n    const txAll=r2?await r2.json():[];\n    let cumul=0;const mtb=document.getElementById("rp-month-rows");mtb.innerHTML="";\n    for(let m=0;m<12;m++){\n      const mStr=String(m+1).padStart(2,"0");\n      const mTxs=txAll.filter(t=>(t.date_reception||"").split("-")[1]===mStr);\n      if(!mTxs.length)continue;\n      const mEng=mTxs.filter(t=>t.status==="validated").reduce((s,t)=>s+t.montant,0);\n      const mPnd=mTxs.filter(t=>t.status==="pending").reduce((s,t)=>s+t.montant,0);\n      cumul+=mEng;\n      const mPct=d.total_budget?Math.round(cumul/d.total_budget*100):0;\n      const col=mPct>90?"#ff4444":mPct>70?"#ffb300":"#00e676";\n      mtb.innerHTML+=`<tr><td style="font-weight:600;color:#c8daf0">${MOIS_EN[m]} / ${MOIS_FR[m]}</td>\n        <td class="num"><span style="background:rgba(0,80,200,.2);color:#60b0f0;border-radius:4px;padding:2px 6px;font-weight:700">${mTxs.length}</span></td>\n        <td class="num" style="color:#00e676;font-weight:700">${fmtFCFA(mEng)}</td>\n        <td class="num" style="color:#ffb300">${fmtFCFA(mPnd)}</td>\n        <td class="num" style="color:#e2eaff;font-weight:700">${fmtFCFA(cumul)}</td>\n        <td><div style="display:flex;align-items:center;gap:5px;min-width:80px"><div style="flex:1;height:5px;background:rgba(0,40,100,.4);border-radius:3px;overflow:hidden"><div style="height:100%;width:${Math.min(100,mPct)}%;background:linear-gradient(90deg,${col}88,${col});box-shadow:0 0 4px ${col};border-radius:3px;"></div></div><span style="font-size:10px;color:${col};font-weight:800">${mPct}%</span></div></td>\n      </tr>`;\n    }\n    if(!mtb.innerHTML)mtb.innerHTML=\'<tr><td colspan="6" style="text-align:center;padding:16px;color:#5a8aaa">No transactions for this year</td></tr>\';\n  }else{breakDiv.style.display="none";}\n  // Direction table\n  const bld=d.bl_by_dir||{};const tb=document.getElementById("rp-dir-rows");tb.innerHTML="";\n  if(!Object.keys(bld).length){tb.innerHTML=\'<tr><td colspan="6" style="text-align:center;padding:20px;color:#5a8aaa">No budget data for this selection</td></tr>\';return;}\n  Object.keys(bld).sort().forEach(dir=>{\n    const bd=bld[dir];const av=bd.budget_cp-bd.engage;\n    const p2=bd.budget_cp?Math.min(100,Math.round(bd.engage/bd.budget_cp*100)):0;\n    const col=p2>90?"#ff4444":p2>70?"#ffb300":"#00e676";\n    tb.innerHTML+=`<tr><td style="font-weight:700"><span class="dir-b">${dir}</span></td>\n      <td class="num" style="font-weight:700;color:#e2eaff">${fmtFCFA(bd.budget_cp)}</td>\n      <td class="num" style="color:#ff6b6b;font-weight:700">${fmtFCFA(bd.engage)}</td>\n      <td class="num" style="color:${av>=0?"#00e676":"#ff4444"};font-weight:700">${fmtFCFA(av)}</td>\n      <td><div style="display:flex;align-items:center;gap:5px;min-width:90px"><div style="flex:1;height:5px;background:rgba(0,40,100,.4);border-radius:3px;overflow:hidden"><div style="height:100%;width:${p2}%;background:linear-gradient(90deg,${col}88,${col});border-radius:3px;box-shadow:0 0 5px ${col};"></div></div><span style="font-size:10px;color:${col};font-weight:800">${p2}%</span></div></td>\n      <td>${av>=0?"<span class=\\"sb-ok\\">OK</span>":"<span class=\\"sb-dep\\">⚠ OVERSHOOT</span>"}</td>\n    </tr>`;\n  });\n}\nfunction downloadReport(){\n  const yr=document.getElementById("rp-year").value||S.year;\n  const mo=document.getElementById("rp-month").value;\n  window.open(`/api/report/monthly?year=${yr}&month=${mo}`,"_blank");\n}\n\nfunction onFileSel(inp,nId,aId){const f=inp.files[0];if(!f)return;document.getElementById(nId).textContent="✓ "+f.name;document.getElementById(aId).style.borderColor="#16a34a";document.getElementById(aId).style.background="#f0fdf4";}\nasync function importTx(){\n  const f=document.getElementById("imp-tx-file").files[0];const yr=Number(document.getElementById("imp-tx-year").value);\n  if(!f){toast("Sélectionnez un fichier CSV",false);return;}\n  if(!yr){toast("Saisissez une année",false);return;}\n  const fd=new FormData();fd.append("file",f);fd.append("year",yr);\n  const r=await api("/api/import/transactions",{method:"POST",body:fd});if(!r)return;\n  const d=await r.json();\n  const errH=d.errors.length?`<details style="margin-top:4px"><summary style="cursor:pointer;font-size:10px">Voir ${d.errors.length} erreur(s)</summary><div style="font-size:10px;max-height:80px;overflow-y:auto">${d.errors.slice(0,10).join("<br>")}</div></details>`:"";\n  document.getElementById("imp-tx-result").innerHTML=`<div class="alrt ${d.errors.length?"alrt-y":"alrt-g"}">${d.created} transaction(s) importée(s).${errH}</div>`;\n  if(d.created){\n    BL_CACHE={};\n    await refreshUserMeta();\n    const tfYear=document.getElementById("tx-f-year");\n    if(tfYear){tfYear.value="";tfYear._userPicked=false;}\n    const importedYear=document.getElementById("imp-tx-year")?.value;\n    if(importedYear){const gY=document.getElementById("g-year");if(gY){let o=Array.from(gY.options).find(x=>x.value==importedYear);if(!o){o=document.createElement("option");o.value=importedYear;o.textContent=importedYear;gY.appendChild(o);}gY.value=importedYear;S.year=Number(importedYear);}}\n    showTab("transactions");await loadTx();await loadKPIs();await loadDash();\n    toast("✅ "+d.created+" transaction(s) importée(s) — Tableau de bord mis à jour","#16a34a");\n  }\n}\nasync function importBL(){\n  const f=document.getElementById("imp-bl-file").files[0];\n  if(!f){toast("Sélectionnez un fichier CSV",false);return;}\n  const fd=new FormData();fd.append("file",f);\n  const r=await api("/api/import/budget-lines",{method:"POST",body:fd});if(!r)return;\n  const d=await r.json();\n  const errH=d.errors.length?`<details style="margin-top:4px"><summary style="cursor:pointer;font-size:10px">Voir ${d.errors.length} erreur(s)</summary><div style="font-size:10px;max-height:80px;overflow-y:auto">${d.errors.slice(0,10).join("<br>")}</div></details>`:"";\n  document.getElementById("imp-bl-result").innerHTML=`<div class="alrt ${d.errors.length?"alrt-y":"alrt-g"}">${d.created} créée(s), ${d.updated} mise(s) à jour.${errH}</div>`;\n  if(d.created||d.updated){BL_CACHE={};toast("Lignes budgétaires importées ✓");loadBL();loadKPIs();}\n}\n\nasync function loadUsers(){\n  const r=await api("/api/users");if(!r)return;const data=await r.json();\n  const rl={admin:"Administrateur",dcf_dir:"Dir. DCF",dcf_sub:"S-Dir. Budget",agent:"Agent",viewer:"Observateur"};\n  const rb={admin:"#991b1b",dcf_dir:"#991b1b",dcf_sub:"#d97706",agent:"#1f4d8f",viewer:"#374151"};\n  document.getElementById("usr-rows").innerHTML=data.map(u=>{\n    let dirs="—";try{const d=JSON.parse(u.directions||"[]");dirs=d.length===ALL_DIRS.length?"Toutes ("+ALL_DIRS.length+")":d.length?d.slice(0,5).join(", ")+(d.length>5?"…":""):"Aucune";}catch{}\n    return `<tr><td><strong>${u.full_name||u.username}</strong></td><td style="font-family:monospace;font-size:11px">${u.username}</td><td style="font-size:11px">${u.email||"—"}</td><td><span style="display:inline-block;padding:2px 7px;border-radius:4px;font-size:10px;font-weight:800;background:${rb[u.role]||"#1f4d8f"};color:#fff">${rl[u.role]||u.role}</span></td><td style="font-size:10px;max-width:200px;overflow:hidden;text-overflow:ellipsis">${dirs}</td><td style="font-size:10px;color:var(--muted)">${(u.created_at||"").slice(0,10)}</td><td style="white-space:nowrap"><button class="btn bs bxs" onclick="editUser(${u.id})">✏</button>${u.username!==S.user?.u?` <button class="btn bd bxs" onclick="delUser(${u.id})">🗑</button>`:"<span style=\\"font-size:9px;color:var(--muted)\\">Vous</span>"}</td></tr>`;\n  }).join("");\n}\nfunction openUserModal(){S.editUserId=null;document.getElementById("usr-modal-title").textContent="Ajouter un utilisateur";["u-nm","u-usr","u-em"].forEach(id=>document.getElementById(id).value="");document.getElementById("u-pw").value="";document.getElementById("u-rl").value="agent";buildDirCheckboxes([]);onRoleChange();openModal("usr-modal");}\nasync function editUser(id){\n  S.editUserId=id;const r=await api("/api/users");if(!r)return;\n  const u=(await r.json()).find(x=>x.id===id);if(!u)return;\n  document.getElementById("usr-modal-title").textContent="Modifier: "+u.username;\n  ["u-nm","u-usr","u-em"].forEach(id2=>document.getElementById(id2).value=u[id2.replace("u-","").replace("nm","full_name").replace("usr","username").replace("em","email")]||"");\n  document.getElementById("u-pw").value="";document.getElementById("u-rl").value=u.role;\n  let dirs=[];try{dirs=JSON.parse(u.directions||"[]");}catch{}\n  buildDirCheckboxes(dirs);onRoleChange();openModal("usr-modal");\n}\nfunction buildDirCheckboxes(sel){document.getElementById("u-dirs-list").innerHTML=ALL_DIRS.map(d=>`<div class="cbox-row"><input type="checkbox" id="dir-${d}" value="${d}" ${sel.includes(d)?"checked":""}><label for="dir-${d}" style="font-size:11px;cursor:pointer;font-weight:600">${d}</label></div>`).join("");}\nfunction selAllDirs(v){document.querySelectorAll("#u-dirs-list input").forEach(c=>c.checked=v);}\nfunction onRoleChange(){const fa=["admin","dcf_dir","dcf_sub"].includes(document.getElementById("u-rl").value);document.getElementById("u-dirs-block").style.opacity=fa?.5:1;if(fa)selAllDirs(true);}\nasync function saveUser(){\n  const role=document.getElementById("u-rl").value;\n  const dirs=["admin","dcf_dir","dcf_sub"].includes(role)?ALL_DIRS:[...document.querySelectorAll("#u-dirs-list input:checked")].map(c=>c.value);\n  const nm=document.getElementById("u-nm").value;const usr=document.getElementById("u-usr").value;const pw=document.getElementById("u-pw").value;\n  if(!usr.trim()){toast("Identifiant requis",false);return;}\n  if(!S.editUserId&&!pw){toast("Mot de passe requis pour un nouvel utilisateur",false);return;}\n  const p={username:usr.trim(),full_name:nm.trim(),role,email:document.getElementById("u-em").value.trim(),directions:dirs};\n  if(pw)p.password=pw;\n  const r=await api(S.editUserId?"/api/users/"+S.editUserId:"/api/users",{method:S.editUserId?"PUT":"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(p)});\n  if(!r)return;if(!r.ok){toast("Erreur: "+(await r.text()),false);return;}\n  toast(S.editUserId?"Modifié ✓":"Créé ✓");closeModal("usr-modal");loadUsers();\n}\nasync function delUser(id){if(!confirm("Supprimer?"))return;await api("/api/users/"+id,{method:"DELETE"});toast("Supprimé");loadUsers();}\n\nfunction applyRole(){\n  const role=S.user?.role||"viewer";\n  const fa=isFullAccess();\n  const isViewer=role==="viewer";\n  const canImport=["admin","dcf_dir","dcf_sub","agent_plus"].includes(role);\n  const canCreate=["admin","dcf_dir","dcf_sub"].includes(role);\n  document.querySelectorAll(".admin-only").forEach(e=>e.style.display=fa?"":"none");\n  document.querySelectorAll(".viewer-hide").forEach(e=>e.style.display=(isViewer||role==="agent")?"none":"");\n  // Import/Export tab - visible for admin, dcf, agent+\n  const nim=document.getElementById("nav-import");\n  if(nim) nim.style.display=canImport?"":"none";\n  // Users tab - only full admin\n  if(fa) document.getElementById("nav-users").style.display="";\n  else document.getElementById("nav-users").style.display="none";\n  // Planning tab - visible for admin, dcf, agent+\n  const np=document.getElementById(\'nav-planning\');\n  if(np) np.style.display=canImport?\'\':\'none\';\n  // Language\n  applyLang();\n  // Populate year filter in tx tab\n  if(S.user?.available_years){\n    const fy=document.getElementById("tx-f-year");\n    if(fy){\n      const cur=fy.value;\n      while(fy.options.length>1)fy.remove(1);\n      S.user.available_years.forEach(y=>{const o=document.createElement("option");o.value=y;o.textContent=y;fy.appendChild(o);});\n      if(cur)fy.value=cur;\n    }\n  }\n}\nasync function logout(){await fetch("/api/logout",{method:"POST",credentials:"include"});window.location="/login";}\n\nasync function init(){\n  initYears();\n  const r=await api("/api/me");if(!r)return;\n  S.user=await r.json();\n  document.getElementById("uname").textContent=S.user.name||S.user.u;\n  const rl={admin:"Admin",dcf_dir:"Dir.DCF",dcf_sub:"S-Dir.Budget",agent:"Agent",viewer:"Lecteur"};\n  document.getElementById("urole").textContent=rl[S.user.role]||S.user.role;\n  const dirs=myDirs();populateDirSelects(dirs);applyRole();applyLang();loadPlanComptable();populateSearchYears();\n  await refreshUserMeta();\n  const tfYear=document.getElementById("tx-f-year");\n  if(tfYear){tfYear.value="";tfYear._userPicked=false;}\n  await loadDash();\n  document.getElementById("tx-q").addEventListener("input",()=>debounce(loadTx,350));\n  document.getElementById("bl-q").addEventListener("input",()=>debounce(loadBL,350));\n  document.querySelectorAll(".mbg").forEach(bg=>bg.addEventListener("click",e=>{if(e.target===bg)bg.classList.remove("open");}));\n  setInterval(loadKPIs,30000);\n}\ninit();\n\n// ══════════════════════════════════════════════════\n// BUDGET PLANNING MODULE JS\n// ══════════════════════════════════════════════════\nlet PLAN_DATA = null;  // master data (actions, activites, taches, comptes)\nlet PLAN_LINES = [];   // current modal lines (local before save)\nlet PLAN_SUB_ID = null; // current submission id\n\nasync function loadMasterData() {\n  if (PLAN_DATA) return PLAN_DATA;\n  const r = await api(\'/api/planning/master-data\');\n  if (!r) return null;\n  PLAN_DATA = await r.json();\n  return PLAN_DATA;\n}\n\nfunction fmtMd(n) {\n  if (!n) return \'0\';\n  if (Math.abs(n) >= 1e9) return (n/1e9).toFixed(1) + \' Md\';\n  if (Math.abs(n) >= 1e6) return (n/1e6).toFixed(0) + \' M\';\n  return new Intl.NumberFormat(\'fr-FR\').format(Math.round(n));\n}\n\nasync function loadPlanningDashboard() {\n  const yr = parseInt(document.getElementById(\'plan-year\')?.value || 2025);\n  const r = await api(`/api/planning/summary?year=${yr}`);\n  if (!r) return;\n  const data = await r.json();\n  \n  const cap = document.getElementById(\'plan-capex-total\');\n  const op = document.getElementById(\'plan-opex-total\');\n  const gt = document.getElementById(\'plan-grand-total\');\n  const sc = document.getElementById(\'plan-submissions-count\');\n  if (cap) cap.textContent = fmtMd(data.capex_total) + \' FCFA\';\n  if (op) op.textContent = fmtMd(data.opex_total) + \' FCFA\';\n  if (gt) gt.textContent = fmtMd(data.capex_total + data.opex_total) + \' FCFA\';\n  if (sc) sc.textContent = (data.submissions||[]).length;\n  \n  // Load submissions list\n  const r2 = await api(`/api/planning/submissions?year=${yr}`);\n  if (!r2) return;\n  const subs = await r2.json();\n  renderPlanSubmissions(subs, yr);\n  \n  // Load summary\n  renderPlanSummary(data);\n  \n  // Load reference data\n  await loadMasterData();\n  renderRefData();\n}\n\nfunction renderPlanSubmissions(subs, yr) {\n  const el = document.getElementById(\'plan-submissions-list\');\n  if (!el) return;\n  if (!subs.length) { el.innerHTML = `<div style="text-align:center;color:#94a3b8;padding:20px">Aucune soumission pour ${yr}. Cliquez ➕ Nouveau PTA.</div>`; return; }\n  el.innerHTML = subs.map(s => {\n    const stColor = s.status===\'approved\'?\'#16a34a\':s.status===\'submitted\'?\'#0891b2\':\'#d97706\';\n    const stLabel = s.status===\'approved\'?\'APPROUVÉ\':s.status===\'submitted\'?\'SOUMIS\':\'BROUILLON\';\n    const total = new Intl.NumberFormat(\'fr-FR\').format(Math.round(s.total_ae||0));\n    return `<div style="background:rgba(0,15,50,.5);border:1.5px solid #e2e8f0;border-radius:8px;padding:10px;display:flex;align-items:center;gap:10px">\n      <div style="background:${s.budget_type===\'CAPEX\'?\'#0891b2\':\'#0f766e\'};color:#fff;padding:3px 8px;border-radius:4px;font-size:10px;font-weight:900;flex-shrink:0">${s.budget_type}</div>\n      <div style="flex:1">\n        <div style="font-weight:800;font-size:12px">${s.direction} — PTA ${yr}</div>\n        <div style="font-size:10px;color:#64748b">Par: ${s.submitted_by} · ${s.submitted_at?.split(\'T\')[0]||\'\'}</div>\n      </div>\n      <div style="text-align:right">\n        <div style="font-weight:900;color:#0f766e;font-size:12px">${total} FCFA</div>\n        <div style="font-size:10px;color:${stColor};font-weight:800">${stLabel}</div>\n      </div>\n      <div style="display:flex;gap:4px">\n        <button onclick="openPlanSubmission(${s.id})" style="padding:4px 10px;background:#0f766e;color:#fff;border:none;border-radius:4px;font-weight:700;cursor:pointer;font-size:10px">✏️ Modifier</button>\n        <button onclick="exportPlanById(${s.id})" style="padding:4px 8px;background:#7c3aed;color:#fff;border:none;border-radius:4px;font-weight:700;cursor:pointer;font-size:10px">⬇</button>\n        ${isFullAccess() && s.status===\'submitted\' ? `<button onclick="approvePlan(${s.id})" style="padding:4px 8px;background:#16a34a;color:#fff;border:none;border-radius:4px;font-weight:700;cursor:pointer;font-size:10px">✓</button>` : \'\'}\n      </div>\n    </div>`;\n  }).join(\'\');\n}\n\nfunction renderPlanSummary(data) {\n  const el = document.getElementById(\'plan-summary-content\');\n  if (!el) return;\n  const dirs = Object.entries(data.by_direction||{}).sort((a,b)=>(b[1].total||0)-(a[1].total||0));\n  el.innerHTML = `<table style="width:100%;border-collapse:collapse;font-size:11px">\n    <thead><tr style="background:#0f766e;color:#fff">\n      <th style="padding:6px 10px;text-align:left">DIRECTION</th>\n      <th style="padding:6px 10px;text-align:right">CAPEX</th>\n      <th style="padding:6px 10px;text-align:right">OPEX</th>\n      <th style="padding:6px 10px;text-align:right">TOTAL</th>\n    </tr></thead>\n    <tbody>\n    ${dirs.map(([d,v],i)=>`<tr style="background:${i%2?\'#f8fafc\':\'#fff\'}">\n      <td style="padding:5px 10px;font-weight:700">${d}</td>\n      <td style="padding:5px 10px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(v.CAPEX||0))}</td>\n      <td style="padding:5px 10px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(v.OPEX||0))}</td>\n      <td style="padding:5px 10px;text-align:right;font-weight:900;color:#0f766e;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(v.total||0))}</td>\n    </tr>`).join(\'\')}\n    </tbody>\n    <tfoot><tr style="background:#1e3a8a;color:#fff;font-weight:900">\n      <td style="padding:6px 10px">TOTAL GÉNÉRAL</td>\n      <td style="padding:6px 10px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(data.capex_total||0))}</td>\n      <td style="padding:6px 10px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(data.opex_total||0))}</td>\n      <td style="padding:6px 10px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round((data.capex_total||0)+(data.opex_total||0)))}</td>\n    </tr></tfoot>\n  </table>`;\n}\n\nfunction renderRefData() {\n  if (!PLAN_DATA) return;\n  filterRefActions();\n  filterRefActivites();\n  filterRefTaches();\n}\n\nfunction filterRefActions() {\n  if (!PLAN_DATA) return;\n  const q = (document.getElementById(\'ref-action-q\')?.value||\'\').toLowerCase();\n  const el = document.getElementById(\'ref-actions-list\');\n  if (!el) return;\n  const items = Object.entries(PLAN_DATA.actions||{})\n    .filter(([k,v]) => !q || k.toLowerCase().includes(q) || (v.lib||\'\').toLowerCase().includes(q))\n    .slice(0,50);\n  el.innerHTML = items.map(([k,v])=>`<div style="padding:3px 8px;border-bottom:1px solid rgba(0,80,160,.2);cursor:pointer" onclick="copyToClipboard(\'${k}\')">\n    <span style="font-weight:700;color:#0f766e">${k}</span> — ${(v.lib||\'\').substring(0,60)}</div>`).join(\'\') || \'<div style="padding:8px;color:#94a3b8">Aucun résultat</div>\';\n}\n\nfunction filterRefActivites() {\n  if (!PLAN_DATA) return;\n  const q = (document.getElementById(\'ref-act-q\')?.value||\'\').toLowerCase();\n  const el = document.getElementById(\'ref-activites-list\');\n  if (!el) return;\n  const items = Object.entries(PLAN_DATA.activites||{})\n    .filter(([k,v]) => !q || k.toLowerCase().includes(q) || (v.lib||\'\').toLowerCase().includes(q))\n    .slice(0,50);\n  el.innerHTML = items.map(([k,v])=>`<div style="padding:3px 8px;border-bottom:1px solid rgba(0,80,160,.2);cursor:pointer" onclick="copyToClipboard(\'${k}\')">\n    <span style="font-weight:700;color:#0891b2">${k}</span> — ${(v.lib||\'\').substring(0,60)}</div>`).join(\'\') || \'<div style="padding:8px;color:#94a3b8">Aucun résultat</div>\';\n}\n\nfunction filterRefTaches() {\n  if (!PLAN_DATA) return;\n  const q = (document.getElementById(\'ref-tache-q\')?.value||\'\').toLowerCase();\n  const el = document.getElementById(\'ref-taches-list\');\n  if (!el) return;\n  const items = Object.entries(PLAN_DATA.taches||{})\n    .filter(([k,v]) => !q || k.toLowerCase().includes(q) || (v.lib||\'\').toLowerCase().includes(q))\n    .slice(0,80);\n  el.innerHTML = items.map(([k,v])=>`<div style="padding:3px 8px;border-bottom:1px solid rgba(0,80,160,.2);cursor:pointer" onclick="copyToClipboard(\'${k}\')">\n    <span style="font-weight:700;color:#7c3aed">${k}</span> — ${(v.lib||\'\').substring(0,80)}</div>`).join(\'\') || \'<div style="padding:8px;color:#94a3b8">Aucun résultat</div>\';\n}\n\nfunction copyToClipboard(text) {\n  navigator.clipboard.writeText(text).then(()=>toast(\'Code copié: \'+text,\'#0f766e\'));\n}\n\nfunction showPlanTab(tab) {\n  [\'mine\',\'summary\',\'ref\'].forEach(t => {\n    const el = document.getElementById(`plan-${t}-panel`);\n    const btn = document.getElementById(`ptab-${t}`);\n    if (el) el.style.display = t===tab?\'\':\'none\';\n    if (btn) { btn.style.background = t===tab?\'#0f766e\':\'#e2e8f0\'; btn.style.color = t===tab?\'#fff\':\'#475569\'; }\n  });\n  if (tab === \'summary\') renderPlanSummary(window._lastPlanSummary||{});\n  if (tab === \'ref\') { loadMasterData().then(()=>renderRefData()); }\n}\n\nasync function showPlanSubModal(defaultType) {\n  await loadMasterData();\n  PLAN_LINES = [];\n  PLAN_SUB_ID = null;\n  document.getElementById(\'pmod-sid\').value = \'\';\n  document.getElementById(\'pmod-status\').textContent = \'BROUILLON\';\n  document.getElementById(\'pmod-type\').value = defaultType || \'OPEX\';\n  document.getElementById(\'pmod-modal-title\')?.dispatchEvent(new Event(\'change\'));\n  document.getElementById(\'plan-modal-title\').textContent = \'📊 Nouveau PTA — \' + (defaultType||\'OPEX\');\n  \n  // Populate direction selector\n  const dirSel = document.getElementById(\'pmod-dir\');\n  if (dirSel && S.user) {\n    const dirs = S.user.direction_list || myDirs();\n    dirSel.innerHTML = dirs.map(d=>`<option value="${d}">${d}</option>`).join(\'\');\n  }\n  \n  filterPlanActions();\n  filterPlanComptes();\n  renderPlanLinesTable();\n  document.getElementById(\'plan-sub-modal\').style.display = \'flex\';\n}\n\nasync function openPlanSubmission(sid) {\n  await loadMasterData();\n  const r = await api(`/api/planning/submissions/${sid}`);\n  if (!r) return;\n  const {submission: s, lines} = await r.json();\n  PLAN_SUB_ID = sid;\n  PLAN_LINES = lines.map(l => ({...l, _saved: true}));\n  document.getElementById(\'pmod-sid\').value = sid;\n  document.getElementById(\'pmod-type\').value = s.budget_type;\n  document.getElementById(\'pmod-status\').textContent = s.status.toUpperCase();\n  document.getElementById(\'plan-modal-title\').textContent = `📊 PTA ${s.direction} ${s.year} — ${s.budget_type}`;\n  \n  const dirSel = document.getElementById(\'pmod-dir\');\n  if (dirSel) {\n    const dirs = S.user?.direction_list || myDirs();\n    dirSel.innerHTML = dirs.map(d=>`<option value="${d}" ${d===s.direction?\'selected\':\'\'}>${d}</option>`).join(\'\');\n  }\n  filterPlanActions();\n  filterPlanComptes();\n  renderPlanLinesTable();\n  document.getElementById(\'plan-sub-modal\').style.display = \'flex\';\n}\n\nfunction closePlanModal() {\n  document.getElementById(\'plan-sub-modal\').style.display = \'none\';\n  loadPlanningDashboard();\n}\n\n// Cascading selectors\nfunction filterPlanActions() {\n  if (!PLAN_DATA) return;\n  const spFilter = document.getElementById(\'pmod-sp\')?.value || \'\';\n  const sel = document.getElementById(\'pmod-aa\');\n  if (!sel) return;\n  const actions = Object.entries(PLAN_DATA.actions||{})\n    .filter(([k,v]) => !spFilter || v.sp === spFilter);\n  sel.innerHTML = \'<option value="">— Action AA —</option>\' + \n    actions.map(([k,v])=>`<option value="${k}" data-lib="${(v.lib||\'\').replace(/"/g,"\'")}">${k} — ${(v.lib||\'\').substring(0,50)}</option>`).join(\'\');\n  filterPlanActivites();\n}\n\nfunction filterPlanActivites() {\n  if (!PLAN_DATA) return;\n  const aaFilter = document.getElementById(\'pmod-aa\')?.value || \'\';\n  const sel = document.getElementById(\'pmod-va\');\n  if (!sel) return;\n  const acts = Object.entries(PLAN_DATA.activites||{})\n    .filter(([k,v]) => !aaFilter || v.aa === aaFilter);\n  sel.innerHTML = \'<option value="">— Activité VA —</option>\' + \n    acts.map(([k,v])=>`<option value="${k}" data-lib="${(v.lib||\'\').replace(/"/g,"\'")}">${k} — ${(v.lib||\'\').substring(0,50)}</option>`).join(\'\');\n  filterPlanTaches();\n}\n\nfunction filterPlanTaches() {\n  if (!PLAN_DATA) return;\n  const vaFilter = document.getElementById(\'pmod-va\')?.value || \'\';\n  const dirFilter = document.getElementById(\'pmod-dir\')?.value || \'\';\n  const sel = document.getElementById(\'pmod-ta\');\n  if (!sel) return;\n  const tasklist = Object.entries(PLAN_DATA.taches||{})\n    .filter(([k,v]) => {\n      if (vaFilter && v.va && v.va !== vaFilter) return false;\n      if (dirFilter && v.entite && v.entite !== dirFilter) return false;\n      return true;\n    }).slice(0,100);\n  sel.innerHTML = \'<option value="">— Tâche —</option>\' + \n    tasklist.map(([k,v])=>`<option value="${k}" data-lib="${(v.lib||\'\').replace(/"/g,"\'").substring(0,80)}">${k} — ${(v.lib||\'\').substring(0,60)}</option>`).join(\'\');\n}\n\nfunction onTacheSelected() {\n  const sel = document.getElementById(\'pmod-ta\');\n  const opt = sel?.options[sel.selectedIndex];\n  if (opt && opt.value) {\n    const lib = opt.dataset.lib || opt.textContent.split(\' — \').slice(1).join(\' \');\n    const natEl = document.getElementById(\'pmod-nature\');\n    if (natEl && !natEl.value) natEl.value = lib.substring(0,80);\n  }\n}\n\nfunction filterPlanComptes() {\n  if (!PLAN_DATA) return;\n  const q = (document.getElementById(\'pmod-compte-q\')?.value||\'\').toLowerCase();\n  const sel = document.getElementById(\'pmod-compte-sel\');\n  if (!sel) return;\n  const items = (PLAN_DATA.comptes||[])\n    .filter(c => !q || c.code.includes(q.toUpperCase()) || c.nom.toLowerCase().includes(q))\n    .slice(0,80);\n  sel.innerHTML = \'<option value="">— N° Compte —</option>\' +\n    items.map(c=>`<option value="${c.code}" data-nom="${c.nom.replace(/"/g,"\'")}">${c.code} — ${c.nom.substring(0,45)}</option>`).join(\'\');\n}\n\nfunction selectPlanCompte(sel) {\n  const opt = sel.options[sel.selectedIndex];\n  document.getElementById(\'pmod-compte\').value = sel.value;\n  // Auto-fill nature if empty\n  const nat = document.getElementById(\'pmod-nature\');\n  if (nat && !nat.value && opt.dataset.nom) nat.value = opt.dataset.nom.substring(0,60);\n}\n\nfunction calcPlanMontant() {\n  const q = parseFloat(document.getElementById(\'pmod-qtes\')?.value||1);\n  const pu = parseFloat(document.getElementById(\'pmod-pu\')?.value||0);\n  const m = document.getElementById(\'pmod-montant\');\n  if (m) m.value = Math.round(q * pu);\n}\n\nasync function addPlanLine() {\n  const sp = document.getElementById(\'pmod-sp\')?.value||\'\';\n  const spLib = sp ? `SP${sp.replace(\'SP\',\'\')}` : \'\';\n  const aa = document.getElementById(\'pmod-aa\'); const aaV = aa?.value||\'\'; const aaL = aa?.options[aa?.selectedIndex]?.dataset?.lib||\'\';\n  const va = document.getElementById(\'pmod-va\'); const vaV = va?.value||\'\'; const vaL = va?.options[va?.selectedIndex]?.dataset?.lib||\'\';\n  const ta = document.getElementById(\'pmod-ta\'); const taV = ta?.value||document.getElementById(\'pmod-ta-libre\')?.value||\'\'; \n  const taL = ta?.options[ta?.selectedIndex]?.dataset?.lib || document.getElementById(\'pmod-ta-libre\')?.value || \'\';\n  const compte = document.getElementById(\'pmod-compte\')?.value||\'\';\n  const nature = document.getElementById(\'pmod-nature\')?.value?.trim();\n  const qtes = parseFloat(document.getElementById(\'pmod-qtes\')?.value||1);\n  const pu = parseFloat(document.getElementById(\'pmod-pu\')?.value||0);\n  const montant = parseFloat(document.getElementById(\'pmod-montant\')?.value||0);\n  const cp1 = parseFloat(document.getElementById(\'pmod-cp1\')?.value||0);\n  const cp2 = parseFloat(document.getElementById(\'pmod-cp2\')?.value||0);\n  const notes = document.getElementById(\'pmod-line-notes\')?.value||\'\';\n  \n  if (!nature) { toast(\'⚠ Libellé/Nature requis\',\'#dc2626\'); return; }\n  if (montant <= 0) { toast(\'⚠ Montant doit être > 0\',\'#dc2626\'); return; }\n  \n  const lineData = {\n    sp_code:sp, sp_lib:spLib, aa_code:aaV, aa_lib:aaL,\n    va_code:vaV, va_lib:vaL, ta_code:taV, ta_lib:taL,\n    compte, nature, qtes, pu, montant_ae:montant,\n    cp_year:montant, cp_year_plus1:cp1, cp_year_plus2:cp2, notes\n  };\n  \n  // If we have a saved submission, save to API\n  if (PLAN_SUB_ID) {\n    const r = await api(`/api/planning/submissions/${PLAN_SUB_ID}/lines`, {method:\'POST\',body:JSON.stringify(lineData)});\n    if (!r) return;\n    const resp = await r.json();\n    lineData.id = resp.id;\n    lineData._saved = true;\n    const totalEl = document.getElementById(\'pmod-total\');\n    if (totalEl) totalEl.textContent = new Intl.NumberFormat(\'fr-FR\').format(Math.round(resp.total_ae||0));\n    toast(\'Ligne ajoutée ✓\',\'#0f766e\');\n  }\n  \n  PLAN_LINES.push(lineData);\n  renderPlanLinesTable();\n  \n  // Reset form fields\n  [\'pmod-qtes\',\'pmod-pu\',\'pmod-montant\',\'pmod-cp1\',\'pmod-cp2\'].forEach(id => {\n    const el = document.getElementById(id); if (el) el.value = id.includes(\'qtes\') ? 1 : 0;\n  });\n  [\'pmod-nature\',\'pmod-ta-libre\',\'pmod-compte-q\',\'pmod-line-notes\'].forEach(id => {\n    const el = document.getElementById(id); if (el) el.value = \'\';\n  });\n  document.getElementById(\'pmod-compte\').value = \'\';\n}\n\nfunction renderPlanLinesTable() {\n  const tbody = document.getElementById(\'pmod-lines-tbody\');\n  const cntEl = document.getElementById(\'pmod-line-count\');\n  const totEl = document.getElementById(\'pmod-total\');\n  if (!tbody) return;\n  if (!PLAN_LINES.length) {\n    tbody.innerHTML = \'<tr><td colspan="8" style="text-align:center;padding:12px;color:#94a3b8">Aucune ligne.</td></tr>\';\n    if (cntEl) cntEl.textContent = \'0\';\n    if (totEl) totEl.textContent = \'0\';\n    return;\n  }\n  const total = PLAN_LINES.reduce((s,l) => s + (l.montant_ae||0), 0);\n  if (cntEl) cntEl.textContent = PLAN_LINES.length;\n  if (totEl) totEl.textContent = new Intl.NumberFormat(\'fr-FR\').format(Math.round(total));\n  tbody.innerHTML = PLAN_LINES.map((l,i) => `<tr style="background:${i%2?\'#f8fafc\':\'#fff\'}">\n    <td style="padding:3px 6px;white-space:nowrap">${l.sp_code||\'\'}</td>\n    <td style="padding:3px 6px;max-width:120px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${l.ta_code} — ${l.ta_lib||\'\'}">${l.ta_code||\'\'}</td>\n    <td style="padding:3px 6px;font-family:monospace;font-weight:700">${l.compte||\'\'}</td>\n    <td style="padding:3px 6px;max-width:140px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${l.nature||\'\'}">${(l.nature||\'\').substring(0,35)}</td>\n    <td style="padding:3px 6px;text-align:right">${l.qtes||1}</td>\n    <td style="padding:3px 6px;text-align:right;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(l.pu||0))}</td>\n    <td style="padding:3px 6px;text-align:right;font-weight:900;color:#0f766e;font-family:monospace">${new Intl.NumberFormat(\'fr-FR\').format(Math.round(l.montant_ae||0))}</td>\n    <td style="padding:3px 6px;text-align:center">\n      <button onclick="delPlanLine(${i})" style="padding:2px 6px;background:#dc2626;color:#fff;border:none;border-radius:3px;cursor:pointer;font-size:10px">✕</button>\n    </td>\n  </tr>`).join(\'\');\n}\n\nasync function delPlanLine(idx) {\n  const line = PLAN_LINES[idx];\n  if (line?.id && PLAN_SUB_ID) {\n    await api(`/api/planning/lines/${line.id}`, {method:\'DELETE\'});\n  }\n  PLAN_LINES.splice(idx, 1);\n  renderPlanLinesTable();\n}\n\nasync function savePlanSubmission() {\n  const dir = document.getElementById(\'pmod-dir\')?.value;\n  const yr = parseInt(document.getElementById(\'pmod-year\')?.value||2025);\n  const btype = document.getElementById(\'pmod-type\')?.value||\'OPEX\';\n  if (!dir) { toast(\'⚠ Direction requise\',\'#dc2626\'); return; }\n  \n  if (!PLAN_SUB_ID) {\n    // Create submission first\n    const r = await api(\'/api/planning/submissions\', {method:\'POST\', body:JSON.stringify({direction:dir,year:yr,budget_type:btype})});\n    if (!r) return;\n    const resp = await r.json();\n    PLAN_SUB_ID = resp.id;\n    document.getElementById(\'pmod-sid\').value = resp.id;\n    \n    // Now save all pending lines\n    for (const line of PLAN_LINES) {\n      if (!line._saved) {\n        const r2 = await api(`/api/planning/submissions/${PLAN_SUB_ID}/lines`, {method:\'POST\',body:JSON.stringify(line)});\n        if (r2) { const resp2 = await r2.json(); line.id = resp2.id; line._saved = true; }\n      }\n    }\n    toast(\'PTA créé et sauvegardé ✓\',\'#0f766e\');\n  } else {\n    toast(\'PTA sauvegardé ✓\',\'#0f766e\');\n  }\n}\n\nasync function submitPlan() {\n  await savePlanSubmission();\n  if (!PLAN_SUB_ID) return;\n  if (!confirm(\'Confirmer la soumission du PTA? (Il sera envoyé au DCF pour approbation)\')) return;\n  const r = await api(`/api/planning/submissions/${PLAN_SUB_ID}/submit`, {method:\'POST\'});\n  if (r) { toast(\'PTA soumis ✓\',\'#0891b2\'); closePlanModal(); }\n}\n\nasync function approvePlan(sid) {\n  if (!confirm(\'Approuver ce PTA?\')) return;\n  const r = await api(`/api/planning/submissions/${sid}/approve`, {method:\'POST\'});\n  if (r) { toast(\'PTA approuvé ✓\',\'#16a34a\'); loadPlanningDashboard(); }\n}\n\nfunction exportPlan() {\n  if (!PLAN_SUB_ID) { toast(\'⚠ Sauvegardez d\'abord le PTA\',\'#f59e0b\'); return; }\n  window.open(`/api/planning/export/${PLAN_SUB_ID}`, \'_blank\');\n}\n\nfunction exportPlanById(sid) {\n  window.open(`/api/planning/export/${sid}`, \'_blank\');\n}\n\nwindow._lastPlanSummary = {};\n\n</script>\n\n  <!-- ══ PLANNING TAB ══════════════════════════════════════ -->\n  <div id="tab-planning" class="tab-content" style="display:none">\n    <div style="background:linear-gradient(135deg,#0f766e,#134e4a);color:#fff;padding:12px 16px;border-radius:10px;margin-bottom:10px;display:flex;align-items:center;gap:12px">\n      <span style="font-size:22px">📊</span>\n      <div><div style="font-size:13px;font-weight:900">PLANIFICATION BUDGÉTAIRE — PTA / CAPEX / OPEX</div><div style="font-size:10px;opacity:.85">Plan de Travail Annuel · Consolidation directionnelle</div></div>\n      <div style="margin-left:auto;display:flex;gap:6px">\n        <select id="plan-year" onchange="loadPlanningDashboard()" style="padding:5px 10px;font-weight:800;border:none;border-radius:5px;color:#0f766e"><option value="2026">2026</option><option value="2025" selected>2025</option><option value="2024">2024</option></select>\n        <button onclick="showPlanSubModal(\'OPEX\')" style="padding:6px 14px;background:#0891b2;color:#fff;border:none;border-radius:5px;font-weight:800;cursor:pointer">➕ Nouveau PTA</button>\n        <button onclick="loadPlanningDashboard()" style="padding:6px 10px;background:rgba(255,255,255,.15);color:#fff;border:1px solid rgba(255,255,255,.3);border-radius:5px;cursor:pointer">↻</button>\n      </div>\n    </div>\n    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:10px">\n      <div class="kpi" style="border-left:4px solid #0891b2"><label>CAPEX TOTAL</label><div class="kv" id="plan-capex-total" style="color:#0891b2">—</div></div>\n      <div class="kpi" style="border-left:4px solid #0f766e"><label>OPEX TOTAL</label><div class="kv" id="plan-opex-total" style="color:#0f766e">—</div></div>\n      <div class="kpi" style="border-left:4px solid #7c3aed"><label>BUDGET TOTAL</label><div class="kv" id="plan-grand-total" style="color:#7c3aed">—</div></div>\n      <div class="kpi" style="border-left:4px solid #d97706"><label>SOUMISSIONS</label><div class="kv" id="plan-submissions-count" style="color:#d97706">—</div></div>\n    </div>\n    <div style="display:flex;gap:4px;margin-bottom:8px;border-bottom:2px solid #e2e8f0">\n      <button id="ptab-mine" onclick="showPlanTab(\'mine\')" style="padding:6px 14px;background:#0f766e;color:#fff;border:none;border-radius:5px 5px 0 0;font-weight:700;cursor:pointer">📋 Mes PTAs</button>\n      <button id="ptab-summary" onclick="showPlanTab(\'summary\')" style="padding:6px 14px;background:rgba(0,60,120,.4);color:#a0c0e0;border:none;border-radius:5px 5px 0 0;font-weight:700;cursor:pointer">📊 Consolidé</button>\n      <button id="ptab-ref" onclick="showPlanTab(\'ref\')" style="padding:6px 14px;background:rgba(0,60,120,.4);color:#a0c0e0;border:none;border-radius:5px 5px 0 0;font-weight:700;cursor:pointer">📚 Réf.</button>\n    </div>\n    <div id="plan-mine-panel"><div id="plan-submissions-list" style="display:flex;flex-direction:column;gap:6px"><div style="color:#94a3b8;text-align:center;padding:20px">Cliquez ↻ pour charger</div></div></div>\n    <div id="plan-summary-panel" style="display:none"><div id="plan-summary-content"><div style="color:#94a3b8;text-align:center;padding:20px">Aucune donnée.</div></div></div>\n    <div id="plan-ref-panel" style="display:none">\n      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px">\n        <div><div style="font-weight:800;color:#0f766e;font-size:11px;margin-bottom:4px">ACTIONS (AA)</div><input id="ref-action-q" oninput="filterRefActions()" placeholder="Rechercher..." style="width:100%;padding:4px;margin-bottom:4px;border:1px solid #e2e8f0;border-radius:3px;font-size:11px"/><div id="ref-actions-list" style="max-height:220px;overflow-y:auto;border:1px solid #e2e8f0;border-radius:4px;font-size:10px"></div></div>\n        <div><div style="font-weight:800;color:#0891b2;font-size:11px;margin-bottom:4px">ACTIVITÉS (VA)</div><input id="ref-act-q" oninput="filterRefActivites()" placeholder="Rechercher..." style="width:100%;padding:4px;margin-bottom:4px;border:1px solid #e2e8f0;border-radius:3px;font-size:11px"/><div id="ref-activites-list" style="max-height:220px;overflow-y:auto;border:1px solid #e2e8f0;border-radius:4px;font-size:10px"></div></div>\n        <div style="grid-column:1/-1"><div style="font-weight:800;color:#7c3aed;font-size:11px;margin-bottom:4px">TÂCHES (T-codes)</div><input id="ref-tache-q" oninput="filterRefTaches()" placeholder="Rechercher tâche ou code T..." style="width:100%;padding:4px;margin-bottom:4px;border:1px solid #e2e8f0;border-radius:3px;font-size:11px"/><div id="ref-taches-list" style="max-height:180px;overflow-y:auto;border:1px solid #e2e8f0;border-radius:4px;font-size:10px"></div></div>\n      </div>\n    </div>\n  </div>\n  <!-- ══ PTA MODAL ══════════════════════════════════════════ -->\n  <div class="mbg" id="plan-sub-modal" style="display:none">\n    <div class="modal" style="max-width:95vw;width:1000px;max-height:90vh;overflow-y:auto">\n      <div class="mh"><h3 id="plan-modal-title">📊 PTA — Plan de Travail Annuel</h3><button class="mcl" onclick="closePlanModal()">✕</button></div>\n      <div class="mb">\n        <div style="background:rgba(0,40,20,.3);border:1.5px solid #86efac;border-radius:8px;padding:10px;margin-bottom:10px;display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:8px">\n          <div><label style="font-size:9px;font-weight:700">DIRECTION *</label><select id="pmod-dir" style="width:100%;padding:5px;font-weight:700;border:1.5px solid #86efac;border-radius:4px"></select></div>\n          <div><label style="font-size:9px;font-weight:700">ANNÉE *</label><select id="pmod-year" style="width:100%;padding:5px;font-weight:700;border:1.5px solid #86efac;border-radius:4px"><option value="2026">2026</option><option value="2025" selected>2025</option><option value="2024">2024</option></select></div>\n          <div><label style="font-size:9px;font-weight:700">TYPE</label><select id="pmod-type" style="width:100%;padding:5px;font-weight:700;border:1.5px solid #86efac;border-radius:4px"><option value="OPEX">OPEX — Fonctionnement</option><option value="CAPEX">CAPEX — Investissement</option></select></div>\n          <div><label style="font-size:9px;font-weight:700">STATUT</label><div id="pmod-status" style="padding:5px;font-weight:900;color:#0f766e;font-size:12px">BROUILLON</div></div>\n        </div>\n        <input type="hidden" id="pmod-sid" value=""/>\n        <div style="background:rgba(0,40,120,.3);border:1.5px solid #bfdbfe;border-radius:8px;padding:10px;margin-bottom:8px">\n          <div style="font-weight:800;color:#1d4ed8;font-size:11px;margin-bottom:6px">📚 BASE DE DONNÉES DE RÉFÉRENCE</div>\n          <div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:6px">\n            <div><label style="font-size:9px;font-weight:700">SOUS-PROGRAMME</label><select id="pmod-sp" onchange="filterPlanActions()" style="width:100%;padding:4px;font-size:10px;border:1px solid #bfdbfe;border-radius:3px"><option value="">Tous SP</option><option value="SP1">SP1 — Broadband Mobile</option><option value="SP2">SP2 — Aménagement Numérique</option><option value="SP3">SP3 — Hub Numérique</option><option value="SP4">SP4 — Gouvernance</option></select></div>\n            <div><label style="font-size:9px;font-weight:700">ACTION (AA)</label><select id="pmod-aa" onchange="filterPlanActivites()" style="width:100%;padding:4px;font-size:10px;border:1px solid #bfdbfe;border-radius:3px"><option value="">— AA —</option></select></div>\n            <div><label style="font-size:9px;font-weight:700">ACTIVITÉ (VA)</label><select id="pmod-va" onchange="filterPlanTaches()" style="width:100%;padding:4px;font-size:10px;border:1px solid #bfdbfe;border-radius:3px"><option value="">— VA —</option></select></div>\n            <div><label style="font-size:9px;font-weight:700">TÂCHE</label><select id="pmod-ta" onchange="onTacheSelected()" style="width:100%;padding:4px;font-size:10px;border:1px solid #bfdbfe;border-radius:3px"><option value="">— Tâche —</option></select></div>\n          </div>\n        </div>\n        <div style="background:rgba(0,20,60,.5);border:1.5px solid #e2e8f0;border-radius:8px;padding:10px;margin-bottom:8px">\n          <div style="font-weight:800;color:#475569;font-size:11px;margin-bottom:6px">✏️ SAISIE LIGNE BUDGÉTAIRE</div>\n          <div style="display:grid;grid-template-columns:2fr 2fr 1fr 1fr 1fr 1fr;gap:6px;margin-bottom:6px">\n            <div><label style="font-size:9px;font-weight:700">N° COMPTE</label><div style="display:flex;gap:2px"><input id="pmod-compte-q" placeholder="Chercher..." oninput="filterPlanComptes()" style="flex:1;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/><select id="pmod-compte-sel" onchange="selectPlanCompte(this)" style="flex:2;padding:3px;font-size:9px;border:1px solid #e2e8f0;border-radius:3px"><option value="">— Compte —</option></select></div><input type="hidden" id="pmod-compte"/></div>\n            <div><label style="font-size:9px;font-weight:700">NATURE / LIBELLÉ *</label><input id="pmod-nature" placeholder="Nature dépense..." style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n            <div><label style="font-size:9px;font-weight:700">QTES</label><input type="number" id="pmod-qtes" value="1" min="1" oninput="calcPlanMontant()" style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n            <div><label style="font-size:9px;font-weight:700">PU (FCFA)</label><input type="number" id="pmod-pu" value="0" oninput="calcPlanMontant()" style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n            <div><label style="font-size:9px;font-weight:700">MONTANT AE</label><input type="number" id="pmod-montant" readonly style="width:100%;padding:3px;font-size:10px;border:1.5px solid #0f766e;border-radius:3px;background:rgba(0,40,20,.3);font-weight:800;color:#0f766e"/></div>\n            <div style="display:flex;flex-direction:column;justify-content:flex-end"><button onclick="addPlanLine()" style="padding:4px 10px;background:#0f766e;color:#fff;border:none;border-radius:4px;font-weight:800;cursor:pointer;font-size:11px">➕ Ajouter</button></div>\n          </div>\n          <div style="display:grid;grid-template-columns:1fr 1fr 2fr;gap:6px">\n            <div><label style="font-size:9px;font-weight:700">CP AN+1</label><input type="number" id="pmod-cp1" value="0" style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n            <div><label style="font-size:9px;font-weight:700">CP AN+2</label><input type="number" id="pmod-cp2" value="0" style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n            <div><label style="font-size:9px;font-weight:700">NOTES</label><input id="pmod-line-notes" placeholder="Observations..." style="width:100%;padding:3px;font-size:10px;border:1px solid #e2e8f0;border-radius:3px"/></div>\n          </div>\n        </div>\n        <div>\n          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px">\n            <div style="font-weight:800;font-size:11px">LIGNES PTA (<span id="pmod-line-count">0</span>)</div>\n            <div style="font-weight:900;color:#0f766e;font-size:12px">TOTAL AE: <span id="pmod-total">0</span> FCFA</div>\n          </div>\n          <div style="overflow:auto;max-height:250px;border:1px solid #e2e8f0;border-radius:6px">\n            <table style="width:100%;border-collapse:collapse;font-size:9px">\n              <thead style="background:#0f766e;color:#fff;position:sticky;top:0"><tr><th style="padding:4px 6px;text-align:left">SP</th><th style="padding:4px 6px;text-align:left">TÂCHE</th><th style="padding:4px 6px;text-align:left">COMPTE</th><th style="padding:4px 6px;text-align:left">NATURE</th><th style="padding:4px 6px;text-align:right">QT</th><th style="padding:4px 6px;text-align:right">PU</th><th style="padding:4px 6px;text-align:right">MONTANT AE</th><th style="padding:4px 6px">DEL</th></tr></thead>\n              <tbody id="pmod-lines-tbody"><tr><td colspan="8" style="text-align:center;padding:12px;color:#94a3b8">Aucune ligne.</td></tr></tbody>\n            </table>\n          </div>\n        </div>\n        <div style="display:flex;gap:6px;justify-content:flex-end;border-top:1px solid #e2e8f0;padding-top:10px;margin-top:8px">\n          <button onclick="closePlanModal()" style="padding:7px 18px;background:rgba(0,60,120,.4);color:#a0c0e0;border:none;border-radius:5px;font-weight:700;cursor:pointer">Fermer</button>\n          <button onclick="savePlanSubmission()" style="padding:7px 18px;background:#0f766e;color:#fff;border:none;border-radius:5px;font-weight:800;cursor:pointer">💾 Sauvegarder</button>\n          <button onclick="submitPlan()" style="padding:7px 18px;background:#0891b2;color:#fff;border:none;border-radius:5px;font-weight:800;cursor:pointer">📤 Soumettre</button>\n          <button onclick="exportPlan()" style="padding:7px 18px;background:#7c3aed;color:#fff;border:none;border-radius:5px;font-weight:800;cursor:pointer">⬇ CSV</button>\n        </div>\n      </div>\n    </div>\n  </div>\n</body>\n</html>'
